        KnowledgeItem("strategy_001","趋势跟踪策略",Category.STRATEGY,Level.INTERMEDIATE,
            "趋势是你的朋友——顺势交易的核心：识别趋势+跟随趋势。",
            "核心理念：截断亏损，让利润奔跑。定义趋势：更高高+更高低=上升趋势。入场：均线金叉+站上MA20、突破前高、回调MA60反弹。出场：均线死叉、跌破MA60、MACD顶背离。海龟法则：突破20日高买入1单位→每涨0.5ATR加1→最多4→跌破10日低全卖。优势：能抓大行情；劣势：震荡市频繁止损。",ImageType.DIAGRAM, listOf("趋势跟踪","海龟交易","顺势"), listOf("strategy_002","ind_001")),
        KnowledgeItem("strategy_002","网格交易策略",Category.STRATEGY,Level.INTERMEDIATE,
            "震荡市利器——在价格区间内低买高卖赚差价。",
            "原理：设定区间分N格，每格等差挂买卖单。参数：底层选ETF/可转债(不死品种)、区间取历史波动80%、间距=日波动率1-2倍、格数10-20格。优势：无需预测方向。致命风险：单边破网(跌破下限全部被套)。选不会归零品种+保留部分备用金。",ImageType.DIAGRAM, listOf("网格交易","ETF","震荡"), listOf("strategy_001","strategy_003")),
        KnowledgeItem("strategy_003","突破交易策略",Category.STRATEGY,Level.INTERMEDIATE,
            "突破关键价位后顺势入场，短线交易者核心策略。",
            "关键价位：前高前低、均线MA20/60/120、趋势线、布林带轨、整数关口。有效突破三特征：放量+K线实体大+收盘站稳。假突破特征：缩量、长影线打回、收盘未站稳。入场：确认突破→等回踩→回踩不破→入场，止损在突破点下1-2%。盈亏比至少1:2。",ImageType.CHART, listOf("突破","假突破","关键价位"), listOf("strategy_001","kline_006")),
        KnowledgeItem("risk_001","仓位与资金管理",Category.RISK,Level.INTERMEDIATE,
            "仓位管理决定你在市场能活多久。",
            "凯利公式：f=(赔率×胜率-败率)/赔率，实际用÷2。固定比例：单笔最大亏损=总资金×2%，仓位=单笔最大亏损/止损幅度。金字塔加仓：首次30%→盈利加20%→再加15%。持仓数：<10万1-3只、10-50万3-5只、50-100万5-8只。永不满仓保留20%+现金；单日亏5%停手；连亏3次减半仓。",ImageType.FORMULA, listOf("仓位管理","凯利公式","加仓"), listOf("risk_002","futures_002")),
        KnowledgeItem("risk_002","止损的艺术",Category.RISK,Level.BEGINNER,
            "不会止损的人不配做交易。",
            "亏10%需涨11%回本、亏50%需涨100%、亏90%需涨900%。方法：固定比例止损(股票5-10%/期货1-3%)、技术位止损(破前低/MA20/趋势线)、ATR止损(买入价-2×ATR)、时间止损(N天不涨卖出)。纪律：下单即设止损、只下移不上移、不撤销、移动止盈。最大心理障碍：'再等等就回来了'。",ImageType.DIAGRAM, listOf("止损","ATR","回本"), listOf("risk_001","risk_003")),
        KnowledgeItem("risk_003","盈亏比与期望值",Category.RISK,Level.ADVANCED,
            "交易本质是找到正期望值策略——胜率不是全部。",
            "期望值=胜率×平均盈利-败率×平均亏损。30%胜率+1:3盈亏比>70%胜率+1:1盈亏比。提高盈亏比：趋势行情入场、入场靠近支撑/阻力、分批止盈、让利润奔跑。盈亏比<1:1需优化策略。复盘统计每笔交易的盈亏比。",ImageType.FORMULA, listOf("盈亏比","期望值","胜率"), listOf("risk_001","risk_002")),
        KnowledgeItem("psych_001","交易心理误区",Category.PSYCHOLOGY,Level.BEGINNER,
            "贪婪、恐惧、过度自信——最大的敌人是自己。",
            "七大误区：锚定效应(死盯买入价)、处置效应(赚就跑亏就扛)、过度交易(手痒)、确认偏误(只看支持的证据)、近因效应(最近几笔影响判断)、羊群效应(追涨杀跌)、报复性交易(亏了就想翻本加倍下注)。应对：建立交易计划+执行、记录日志复盘、设亏损上限、保持运动睡眠。",ImageType.NONE, listOf("交易心理","锚定效应","羊群效应"), listOf("psych_002","risk_002")),
        KnowledgeItem("psych_002","交易纪律养成",Category.PSYCHOLOGY,Level.INTERMEDIATE,
            "专业和业余的最大区别不是技术，是纪律。",
            "每日流程：盘前(8:30-9:30)浏览隔夜外盘+公告+复盘+计划。盘中(9:30-15:00)按计划执行不为情绪动、达止损止盈就执行、不开计划外仓。盘后(15:00-16:00)复盘+更新日志+分析成败+选股。日志模板：日期/品种/方向/价格/盈亏/理由/改进/心态评分。纪律清单：按计划+设止损+仓位限额内+不情绪交易+盈亏比达标。",ImageType.NONE, listOf("交易纪律","复盘","日志"), listOf("psych_001","risk_001")),
        // ========== 股票基本面（新增） ==========
        KnowledgeItem("basic_006","财务报表入门",Category.BASIC,Level.INTERMEDIATE,
            "三大报表：资产负债表、利润表、现金流量表——选股必看。",
            "**资产负债表**(某日快照)：资产=负债+所有者权益。关键项：货币资金(越多越安全)、应收账款(大增可能虚增收入)、存货(下降好)、商誉(并购溢价太高爆雷)。**利润表**(一段时间)：收入-成本费用=净利润。看营收增速、毛利率、净利率、扣非净利润。**现金流量表**：经营现金流(>0健康)、投资现金流(负=扩张中好)、筹资现金流。自由现金流=经营现金流-资本开支。",ImageType.FORMULA, listOf("财报","三大报表","现金流"), listOf("basic_001","term_001")),
        KnowledgeItem("basic_007","盈利能力指标",Category.BASIC,Level.INTERMEDIATE,
            "毛利率、净利率、ROA、ROIC——判断公司赚钱能力。",
            "毛利率=(收入-成本)/收入(>40%好)。净利率=净利润/收入(>20%优秀)。ROA=净利润/总资产(衡量资产效率)。ROIC=息前税后利润/投入资本(>15%极好)。毛利率高+净利率低=费用管控差。毛利率持续下降=竞争力下降(警惕)。三费：销售费+管理费+研发费，看三费占收入比趋势。",ImageType.FORMULA, listOf("毛利率","净利率","ROA","ROIC"), listOf("term_001","term_003")),
        KnowledgeItem("basic_008","成长性与估值",Category.BASIC,Level.INTERMEDIATE,
            "PEG=PE/净利润增长率，PEG<1=低估。",
            "营收增长率(>20%高成长)、净利增长率(>15%好)。PEG=PE÷净利增速：PEG<1低估、=1合理、>1高估(成长股可放宽到1.5)。PEG陷阱：增速下降PE也降=双杀。股息率=每股股息/股价(>3%好,银行股看)。分红率=股息/EPS(30-60%健康)。PEG无法用于周期股/亏损股。",ImageType.FORMULA, listOf("PEG","成长性","股息率"), listOf("term_001","basic_007")),
        KnowledgeItem("basic_009","技术分析vs基本面",Category.BASIC,Level.BEGINNER,
            "基本面选股，技术面择时——两条腿走路。",
            "基本面：研究公司价值(PE/PB/ROE/财报)、选好公司、长期持有、低估买入。技术面：研究价格图表(K线/均线/指标)、择时、中短期。结合：基本面筛出好公司→等技术面回调到支撑位→入场。误区：基本面好≠股价马上涨(可能低估多年)；技术面涨≠公司好(纯炒作)。彼得林奇：'基本面决定长期，情绪决定短期'。",ImageType.DIAGRAM, listOf("基本面","技术面","择时","选股"), listOf("basic_001","strategy_001")),
        // ========== 期货品种详解（新增） ==========
        KnowledgeItem("futures_005","黑色系品种",Category.FUTURES,Level.BEGINNER,
            "螺纹钢、铁矿石、焦煤、焦炭、热卷——国内最大交易板块。",
            "螺纹钢(RB,10吨/手,保证金约4000元,上期所)：建筑用钢,房建基建需求驱动。铁矿石(I,100吨/手,约1.5万,大商所)：炼铁原料,受政策/钢厂利润/澳巴发运影响。焦炭(J,100吨/手,约5万,大商所)：由焦煤炼成,黑色利润核心。焦煤(JM,60吨/手,约2万,大商所)：焦炭原料。热卷(HC,10吨/手,上期所)：汽车家电用钢。螺纹-铁矿-焦炭=黑色链套利机会。",ImageType.DIAGRAM, listOf("螺纹钢","铁矿石","焦煤","焦炭","黑色系"), listOf("futures_001","futures_002")),
        KnowledgeItem("futures_006","能化品种",Category.FUTURES,Level.BEGINNER,
            "原油、甲醇、PTA、纯碱、玻璃——最活跃板块之一。",
            "原油(SC,1000桶/手,约7万,上期能源)：全球定价,受OPEC+地缘影响大。甲醇(MA,10吨/手,约3000元,郑商所)：化工之母,煤制/气制两种,受煤价影响。PTA(TA,5吨/手,约2500元,郑商所)：涤纶原料,原油-MX-PX-PTA-涤纶长丝链条。纯碱(SA,20吨/手,约4000元,郑商所)：玻璃原料,受光伏玻璃需求驱动。玻璃(FG,20吨/手,约3500元,郑商所)：地产竣工端指标。PVC/PP/PE统称聚烯烃三兄弟(大商所)。",ImageType.DIAGRAM, listOf("原油","甲醇","PTA","纯碱","玻璃","能化"), listOf("futures_001","futures_005")),
        KnowledgeItem("futures_007","农产品期货",Category.FUTURES,Level.BEGINNER,
            "豆粕、菜粕、玉米、生猪、鸡蛋、棉花、白糖——民生板块。",
            "豆粕(M,10吨/手,约3000元,大商所)：饲料之王,USDA报告+天气+压榨利润。菜粕(RM,10吨/手,约2500元,郑商所)：水产饲料,替代豆粕。玉米(C,10吨/手,约2500元,大商所)：饲料/乙醇原料。生猪(LH,16吨/手,约7万,大商所)：周期性强(猪周期3-4年)。鸡蛋(JD,5吨/手,约6000元,大商所)：小品种。棉花(CF,5吨/手,约1万,郑商所)：纺织原料。白糖(SR,10吨/手,约6000元,郑商所)：甘蔗/甜菜,三年周期。苹果(AP)、红枣(CJ)以波动大为特色。",ImageType.DIAGRAM, listOf("豆粕","玉米","生猪","棉花","白糖","农产品"), listOf("futures_001","futures_002")),
        KnowledgeItem("futures_008","有色金属与贵金属",Category.FUTURES,Level.INTERMEDIATE,
            "铜铝锌铅镍锡、金银——工业血液+避险资产。",
            "沪铜(CU,5吨/手,约4万,上期所)：铜博士,全球经济晴雨表,看TC/RC加工费+LME库存。沪铝(AL,5吨/手,约8000元)：地产/汽车轻量化,看电解铝产能天花板。沪锌(ZN,5吨/手,约1.2万)：镀锌板需求。沪镍(NI,1吨/手,约1.5万)：不锈钢+新能源电池。沪锡/沪铅流动性偏低。沪金(AU,1000克/手,约7万)：避险+实际利率负相关,COMEX联动强。沪银(AG,15千克/手,约1.5万)：工业+金融双属性,波动大于黄金。金银比70-80为均衡区。",ImageType.DIAGRAM, listOf("铜","铝","金","银","有色金属"), listOf("futures_001","futures_005")),
        // ========== 期货交易规则（新增） ==========
        KnowledgeItem("futures_009","期货交易制度",Category.FUTURES,Level.BEGINNER,
            "保证金、逐日盯市、涨跌停、限仓、强行平仓——必知制度。",
            "**保证金制度**：交易所按合约价值一定比例收取(5-15%),期货公司上浮1-3%。**逐日盯市**(逐日结算)：每天收盘按结算价计算盈亏,亏了就划钱,不够就追加。**涨跌停板**：大部分±5%-8%,上期所±3%-8%阶梯板。**限仓制度**：单一月份/所有月份对投机头寸设上限,防操纵。**强行平仓**：保证金不足/超仓/违规时交易所强平。**大户报告**：持仓达限仓80%需报告。",ImageType.NONE, listOf("交易制度","逐日盯市","涨跌停","限仓"), listOf("futures_001","risk_001")),
        KnowledgeItem("futures_010","交割与移仓换月",Category.FUTURES,Level.INTERMEDIATE,
            "实物交割vs现金交割，如何避免被动交割。",
            "**实物交割**：商品期货到期后买卖双方交付现货(自然人不允许交割)。**现金交割**：股指期货到期按结算价差额现金结算。自然人最后交易日：合约月份第10个交易日(上期所)或交割月前月最后一个交易日(大商所/郑商所,法人不限制)。**移仓换月**：主力合约快到期时平仓旧合约、开仓新合约。一般换到成交持仓最大的合约。**基差**=现货价-期货价。升水(期货>现货)、贴水(期货<现货)。",ImageType.DIAGRAM, listOf("交割","移仓","基差","升贴水"), listOf("futures_001","futures_009")),
        KnowledgeItem("futures_011","期货手续费计算",Category.FUTURES,Level.BEGINNER,
            "固定值vs万分比，双边收费，日内平今可能免收。",
            "两种收费方式：(1)固定值：每手固定金额,如豆粕1.5元/手、玉米1.2元/手。(2)万分比：按成交金额比例,如螺纹钢万1,4000元×10吨×万1=4元/手。开仓+平仓各收一次(双边)。部分品种平今仓免收或减半(股指期货平今收万3.45,开仓万0.23)。做短线必须算手续费,日内交易手续费是重要成本。不同期货公司手续费差异大(交易所1.1-2倍)。",ImageType.NONE, listOf("手续费","平今","日内"), listOf("futures_001","futures_009")),
        // ========== 期权（新增） ==========
        KnowledgeItem("options_001","期权基础概念",Category.FUTURES,Level.INTERMEDIATE,
            "权利而非义务——买方有选择权,卖方有履约义务。",
            "**看涨期权(Call)**：买方有权在到期日以约定价格(行权价)买入标的。**看跌期权(Put)**：买方有权以行权价卖出标的。**权利金**(期权费)=买方付出的成本=卖方的收入。买方：最大亏损=权利金,收益无限(Call)/有限(Put)。卖方：最大收益=权利金,亏损无限。**美式期权**(到期前任一天行权)/**欧式期权**(仅到期日行权)。国内商品/股指期权多为美式。标的：50ETF、300ETF、沪深300/中证1000股指、铁矿石/豆粕/玉米/PTA等。",ImageType.DIAGRAM, listOf("期权","看涨","看跌","权利金","行权"), listOf("futures_001","options_002")),
        KnowledgeItem("options_002","期权四大策略",Category.FUTURES,Level.ADVANCED,
            "买Call、买Put、卖Call、卖Put——四种基础策略。",
            "1.买Call：看大涨,最大亏=权利金,收益无限。2.买Put：看大跌或对冲持股,最大亏=权利金。3.备兑卖Call(已持有标的)：不看涨或小涨,赚权利金,被行权则卖出标的。4.卖Put：看不大跌,赚权利金,到期低于行权价可能被行权买入。卖跨式(卖Call+卖Put同价)：赌横盘。买跨式(买Call+买Put)：赌大波动。牛市价差(买低行权Call+卖高行权Call)：温和看涨,降低权利金成本。",ImageType.DIAGRAM, listOf("买看涨","买看跌","卖期权","价差策略"), listOf("options_001","options_003")),
        KnowledgeItem("options_003","期权定价与希腊字母",Category.FUTURES,Level.ADVANCED,
            "Delta/Gamma/Theta/Vega——期权价格变动五维。",
            "BS模型：期权价格=f(标的价格,行权价,到期时间,波动率,无风险利率)。**Delta**(方向)：标的变化1单位期权变多少，Call的Delta 0~1,Put -1~0，ATM≈±0.5。**Gamma**(加速度)：Delta变化率,ATM最大。**Theta**(时间衰减)：每天损失多少时间价值,临近到期加速衰减。**Vega**(波动率)：波动率升1%期权涨多少,ATM最大。买方希望高Gamma+低Theta；卖方赚Theta但要防Gamma爆。平值期权(ATM)=最贵+Gamma/Vega最大+Theta衰减最快。",ImageType.FORMULA, listOf("Delta","Gamma","Theta","Vega","希腊字母"), listOf("options_001","options_002")),
        // ========== 期货新手入门（新增） ==========
        KnowledgeItem("futures_012","期货新手开户指南",Category.FUTURES,Level.BEGINNER,
            "从零开始做期货——开户、入金、软件、模拟交易。",
            "开户条件：18周岁+身份证+银行卡,商品期货无资金门槛(股指50万)。流程：选期货公司(看评级/费用)→下载APP→身份证认证→视频验证→风险测评→银期签约(关联银行卡和期货账户)→入金。新手必做：先模拟交易1-2个月(文华财经/博易等有模拟)。推荐学习路径：基础知识→1手轻仓实盘→单品种深耕→建立系统→稳定盈利(一般需1-2年)。首单建议做螺纹钢/玉米等流动性好波动小的品种。",ImageType.DIAGRAM, listOf("开户","新手","模拟交易","银期"), listOf("futures_001","futures_002")),
        KnowledgeItem("futures_013","期货看盘软件",Category.FUTURES,Level.BEGINNER,
            "文华财经、博易大师、快期——三款主流期货软件对比。",
            "**文华财经**(赢顺wh6)：功能全/指标多/云端条件单/付费版可写策略。**博易大师**：简洁流畅/K线画图强/免费/闪电手交易快。**快期**(CTP直连)：速度最快/适合高频/需另外开行情。**同花顺期货通**：手机端好用/资讯快/社区活跃。必备功能：条件单(止损止盈自动)、云端单(关电脑也执行)、画线分析、盘口明细。新手建议博易+文华组合。",ImageType.NONE, listOf("软件","文华财经","博易","快期"), listOf("futures_001","futures_012")),
        // ========== 进阶补充 ==========
        KnowledgeItem("ind_006","WR威廉指标+CCI",Category.INDICATORS,Level.INTERMEDIATE,
            "WR超买超卖、CCI趋势强度——辅助判断利器。",
            "WR(威廉指标)=100×(N日最高-收盘)/(N日最高-N日最低)。0~-20超买(卖出)、-80~-100超卖(买入)。WR碰0向下勾=卖，碰-100向上勾=买。CCI(商品通道指数)=典型值-(N日均值)/0.015×平均偏差。CCI>100超买、<-100超卖。独特：CCI>200极强可追、CCI>300极度超买必回归。WR确认超买超卖,CCI确认趋势强弱。参数WR(14)、CCI(20)。",ImageType.CHART, listOf("WR","威廉指标","CCI"), listOf("ind_001","ind_002","ind_003")),
        KnowledgeItem("ind_007","均线进阶：葛兰碧八大法则",Category.INDICATORS,Level.ADVANCED,
            "均线不仅是金叉死叉——八大买卖点的精妙用法。",
            "买入四信号：1.均线走平向上+K线上穿=买入。2.均线上行+K线回踩均线不破=加仓。3.跌破均线但均线仍上行+快速收复=洗盘买入。4.急跌远离均线(乖离率大)+回归=反弹买入。卖出四信号：5.均线走平向下+K线下穿=卖出。6.均线下行+反弹均线受阻=卖出。7.上穿均线但均线下行+快速回落=诱多卖出。8.急涨远离均线+回归=减仓。核心：均线方向=趋势方向,顺着方向用信号。",ImageType.CHART, listOf("葛兰碧","均线战法","乖离率"), listOf("term_006","ind_001","strategy_001")),
        // ========== 第二轮补充 ==========
        KnowledgeItem("macro_001","宏观经济指标",Category.BASIC,Level.INTERMEDIATE,
            "GDP、CPI、PPI、PMI——看懂这四个指标你就有了宏观框架。",
            "GDP(国内生产总值)：经济体总产出,增速>5%景气,<0衰退。CPI(居民消费价格)：>3%通胀加息利空股市,<0通缩。PPI(工业生产者出厂价)：上游价格,涨利好周期股/跌利好制造业。PMI(制造业PMI)：>50扩张<50收缩,领先指标。社融(社会融资规模)：宽信用利好股市。M2(广义货币)：放水利好资产价格。核心逻辑：经济差+政策松=抄底；经济热+政策紧=减仓。",ImageType.FORMULA, listOf("GDP","CPI","PPI","PMI","宏观"), listOf("basic_001","basic_009")),
        KnowledgeItem("macro_002","货币政策与央行",Category.BASIC,Level.INTERMEDIATE,
            "降准、降息、LPR、MLF——央行的工具箱。",
            "降准(降低存款准备金率)：释放银行放贷能力,流动性宽松利好股市。降息(降低MLF/LPR)：降低全社会资金成本,利好后市。LPR(贷款市场报价利率)：1年期=企业贷,5年期=房贷,每月20日公布。MLF(中期借贷便利)：央妈借钱给银行,利率变动=政策转向信号。逆回购：短期调节工具。美联储：加息=美元强+全球流动性紧+新兴市场承压；降息=美元弱+资金回流A股。关注每月美国CPI和非农数据。",ImageType.DIAGRAM, listOf("降准","降息","LPR","MLF","美联储"), listOf("macro_001","basic_009")),
        KnowledgeItem("macro_003","汇率与大宗商品",Category.BASIC,Level.INTERMEDIATE,
            "人民币汇率如何影响股市和期货——传导机制全解。",
            "人民币升值：外资流入利好消费/金融(但出口企业承压)；进口原材料成本降利好铜/原油/纸浆；利空出口型制造业。人民币贬值：外资流出利空A股、利好纺织/家电等出口企业；进口商品变贵推高国内期货(铁矿石/大豆/原油)。美元指数与大宗负相关：美元强则黄金/原油/铜承压。关注：中美利差、外汇储备变化、央行中间价。外汇期货：离岸CNH/在岸CNY。",ImageType.DIAGRAM, listOf("汇率","人民币","美元","大宗商品"), listOf("macro_001","futures_005","futures_008")),
        KnowledgeItem("basic_010","行业板块分析",Category.BASIC,Level.INTERMEDIATE,
            "消费、科技、周期、金融——四大板块投资逻辑。",
            "消费(食品饮料/医药)：弱周期/业绩稳/长牛集中地/看ROE和品牌护城河。科技(半导体/AI/新能源)：高成长/高波动/看研发投入和行业景气。周期(有色/钢铁/化工)：跟经济周期/利润波动极大/看库存和开工率/买在PE最高时卖在PE最低时。金融(银行/保险/券商)：高杠杆/看利率和政策/银行看息差和不良率/券商看成交量和IPO。板块轮动：复苏→科技,过热→周期,滞涨→消费,衰退→债券/公用事业。",ImageType.DIAGRAM, listOf("行业","板块轮动","消费","科技","周期"), listOf("basic_001","macro_001")),
        KnowledgeItem("basic_011","ETF指数基金",Category.BASIC,Level.BEGINNER,
            "不会选股就买ETF——指数基金是普通人的最佳选择。",
            "ETF(交易型开放式指数基金)：像股票一样买卖一篮子资产。宽基ETF：沪深300(510300)、中证500(510500)、科创50(588000)、创业板(159915)。行业ETF：券商(512880)、半导体(512480)、医药(512010)、白酒(512690)。跨境ETF：纳指(513100)、恒生(159920)。黄金ETF(518880)。优势：分散风险/费用低(年管理费0.15-0.5%)/流动性好/透明。定投策略：每月固定日买、长期持有、微笑曲线。期货对应的ETF：豆粕(159985)、有色(159871)等商品ETF。",ImageType.DIAGRAM, listOf("ETF","指数基金","定投","宽基"), listOf("basic_001","basic_010")),
        KnowledgeItem("basic_012","可转债入门",Category.BASIC,Level.INTERMEDIATE,
            "下有保底上不封顶——可转债的股债双重属性。",
            "可转债=债券+股票看涨期权。面值100元,到期还本付息(保底)。转股价：转换成正股的价格。转股价值=100/转股价×正股价。当正股价>转股价时转债随正股涨。条款：强赎(正股涨到转股价130%以上公司可赎回=必须转股或卖出)、下修(正股跌太多公司可下调转股价=利好)、回售(跌破70%可卖回公司=保底)。打新债：申购可转债1000元,上市多数溢价10-30%=低风险套利。双低策略：价格<120+溢价率<20%筛选。",ImageType.FORMULA, listOf("可转债","打新债","强赎","下修","转股"), listOf("basic_001","options_001")),
        KnowledgeItem("kline_007","持续形态：旗形与楔形",Category.KLINE,Level.INTERMEDIATE,
            "旗形和楔形是趋势中途的休整形态，突破后沿原趋势运行。",
            "旗形：快速涨跌后价格在平行通道内整理=旗面,整理结束突破=沿原趋势。上升旗形：跌后整理的下降通道,向上突破看涨；下降旗形：涨后整理的上升通道,向下突破看跌。旗面成交量递减、突破放量。楔形不同于旗形(两端收敛)：上升楔形倾斜向上但看跌、下降楔形倾斜向下但看涨(与RSI反向背离类似)。楔形突破时间更慢但更可靠。量度目标=旗杆长度。",ImageType.CHART, listOf("旗形","楔形","持续形态"), listOf("kline_003","kline_006")),
        KnowledgeItem("kline_008","圆弧底与V形反转",Category.KLINE,Level.ADVANCED,
            "圆弧底是长期底部，V形反转是剧烈转折——两种极端形态。",
            "圆弧底(碟形底)：长期下跌后成交量逐渐萎缩→底部横盘整理(几周到几月)→成交量渐增温和上涨形成弧线。特征：机构吸筹区,右侧放量突破颈线确认反转。圆弧顶=镜像。V形反转：暴跌后突发利好→极速反弹形成V形,成交量急剧放大。V形是最难抓的反转(不给二次确认)。岛形反转：跳空下跌+横向整理+反向跳空=最强烈的反转信号(缺口不补=多空彻底翻转)。量度目标：圆弧底颈线到最低点距离×1倍。",ImageType.CHART, listOf("圆弧底","V形","岛形反转"), listOf("kline_004","kline_005")),
        KnowledgeItem("futures_014","期货季节性规律",Category.FUTURES,Level.ADVANCED,
            "摸透品种季节性=胜率提升20%。各品种年内规律。",
            "螺纹钢：3-4月开工旺季涨、6-8月淡季跌、9-10月金九银十、冬季限产涨。铁矿石：1-2月补库涨、3-4月高炉复产涨、6月淡季跌。豆粕：3-4月南美收割压力跌、6-8月美豆天气炒作涨、12月南美种植涨。生猪：1月腌腊旺季涨、3-4月消费淡季跌、7-8月高温淡、11月旺季涨。白糖：1-3月榨季高峰跌、5月消费启动、9月双节备货涨。鸡蛋：中秋前8-9月高点、春节后2-3月低点。玻璃：8-10月旺季涨、1-2月春节停工跌。棉花：4月种植+天气、9月新棉上市跌。核心：季节性不是铁律,需结合供需验证。",ImageType.DIAGRAM, listOf("季节性","规律","淡旺季"), listOf("futures_005","futures_006","futures_007")),
        KnowledgeItem("futures_015","库存与仓单分析",Category.FUTURES,Level.ADVANCED,
            "库存是供需的最终结果——读懂库存就读懂价格方向。",
            "库存类型：社会库存(港口+工厂+贸易商)、交易所仓单(期货交割库存)。库存变化=生产+进口-消费-出口。去库存+低库存=利多(如纯碱2023大行情源于低库存)。累库存+高库存=利空(如螺纹淡季垒库)。仓单注册：现货商把货放入交割库=锁定卖出,仓单大增=现货商看跌。仓单注销：从交割库提走货=现货紧,仓单大减=看涨。基差=现货-期货,正基差(现货紧)+低库存=强支撑,负基差(现货松)+高库存=弱。关注每周五交易所仓单日报。",ImageType.DIAGRAM, listOf("库存","仓单","基差","去库存"), listOf("futures_001","futures_010","macro_003")),
        KnowledgeItem("futures_016","套期保值实务",Category.FUTURES,Level.ADVANCED,
            "企业如何用期货锁定成本和利润——产业客户的必修课。",
            "买入套保：担心原材料涨价→提前买入期货锁定成本。如饲料厂买入豆粕期货锁定成本。卖出套保：担心产品跌价→提前卖出期货锁定售价。如钢厂卖出螺纹钢期货锁定利润。套保比率：完全套保(100%对冲)或部分套保(70%对冲)。基差风险：期现价差变动影响套保效果。案例：压榨厂同时买入大豆期货+卖出豆粕豆油期货=压榨利润套保。注意：套保不是投机,不能赌方向,必须有现货对应。",ImageType.DIAGRAM, listOf("套期保值","买入套保","卖出套保"), listOf("futures_001","futures_004","futures_010")),
        KnowledgeItem("strategy_004","常见骗线陷阱",Category.STRATEGY,Level.ADVANCED,
            "假突破、诱多诱空、对倒拉升——主力常用手法揭秘。",
            "假突破：突破前高/颈线后迅速回落,收盘未站稳。判断：放量但未持续+长上影+收盘回破。应对：等3%确认或3天站稳。诱多：拉高出货,盘口挂大买单但不断撤单换成卖单。对倒：同一账户买卖制造放量假象。托单/压单：卖1挂大单后撤单=诱空；买1挂大单后撤单=诱多。尾盘异动：最后3分钟急拉或急砸(操纵收盘价)。极窄横盘后放量选方向=真突破概率大。核心纪律：永远等确认入场,不做第一个承担风险的人。",ImageType.CHART, listOf("骗线","假突破","诱多","盘口语言"), listOf("strategy_003","kline_001","risk_002")),
        KnowledgeItem("strategy_005","龙虎榜与资金流向",Category.STRATEGY,Level.INTERMEDIATE,
            "龙虎榜透露主力动向——游资、机构、北向资金各不同。",
            "龙虎榜：每日涨跌幅±7%/换手率>20%/三日偏离值20%个股上榜。买入前五+卖出前五席位。游资(小仓位+快进快出)：次日溢价或砸盘,看席位名声。机构(买入席位中出现)：中线看好,值得跟踪。北向资金(沪港通+深港通)：外资流入流出,连续净买=看好A股,连续净卖=避险。主力资金净流入/流出：大单统计但不完全可信(主力可用拆单隐藏)。使用：龙虎榜机构扎堆买入+低位首次上榜=最好,高位游资接盘=危险。",ImageType.NONE, listOf("龙虎榜","游资","北向资金","席位"), listOf("strategy_003","basic_010")),
        KnowledgeItem("strategy_006","财经日历与事件驱动",Category.STRATEGY,Level.INTERMEDIATE,
            "重要数据发布时间表——每个交易员必收藏的日历。",
            "每周关注：周一中国PMI(月底)/美国ISM、周三EIA原油库存、周四美国初请失业金、周五中国CPI/PPI(月中)。每月关键：上旬美国非农(每月第一个周五)、中美CPI(月中)、LPR报价(20日)、美联储议息(约6周一次)。农产品重要：USDA月度供需报告(每月10号左右)、MPOB棕榈油报告。重大事件：OPEC+会议(影响原油)、中央经济工作会议(12月)、两会(3月)。策略：数据公布前后减仓或设双向条件单,重大事件前轻仓/空仓。",ImageType.DIAGRAM, listOf("财经日历","非农","USDA","议息"), listOf("macro_001","macro_002","futures_007")),
        KnowledgeItem("strategy_007","量化交易入门",Category.STRATEGY,Level.ADVANCED,
            "回测、夏普比率、最大回撤——策略好不好数字说了算。",
            "回测：用历史数据模拟策略表现,关键指标：总收益率/年化收益率/胜率(>40%好)/盈亏比(>2好)/最大回撤(从最高点到最低点的最大亏损百分比,<20%优秀/<30%合格/>50%放弃)。夏普比率=(年化收益-无风险利率)/年化波动率,>1可用/>2优秀/>3极好。卡玛比率=年化收益/最大回撤,>2优秀。回测陷阱：过度优化(参数拟合历史)、幸存者偏差、滑点未计入。建议：用聚宽/MindGo/VNPy等平台学习,从均线策略开始。",ImageType.FORMULA, listOf("量化","回测","夏普比率","最大回撤"), listOf("strategy_001","risk_003")),
        // ========== 第三轮补充 ==========
        KnowledgeItem("kline_009","三只乌鸦与红三兵",Category.KLINE,Level.INTERMEDIATE,
            "三根K线的力量——最经典的连续形态。",
            "三只乌鸦(顶部)：连续三根阴线,每根开盘在前一根阴线实体内,收盘接近当日最低。出现在涨势末期=强烈看跌。确认：第三根放量+缩量反弹=确认。红三兵(底部)：连续三根阳线,每根收盘高于前一根,实体逐步放大。出现在跌势末期=强烈看涨。确认：成交量递增+突破均线压制。变体：前方受阻型红三兵(实体渐缩+上影渐长)=多头衰竭。前进三兵(实体均衡)=稳健上涨。注意：单纯三根K线必须结合趋势位置和成交量判断。",ImageType.CHART, listOf("三只乌鸦","红三兵","三连阳","三连阴"), listOf("kline_001","kline_002","kline_004")),
        KnowledgeItem("kline_010","孕线与十字星组合",Category.KLINE,Level.ADVANCED,
            "孕线是趋势停顿的信号，十字星代表多空平衡——组合来看才精准。",
            "孕线(Harami)：第二根K线完全被第一根K线包含。顶部孕线(大阳+小阴)=上涨乏力；底部孕线(大阴+小阳)=下跌衰竭。十字孕线(大实体+十字星)=极强反转信号。十字星：开盘=收盘但有影线,多空暂时平衡。长腿十字(上下影都长)=方向选择在即。墓碑十字(上影长无下影)=顶部信号。蜻蜓十字(下影长无上影)=底部信号。晨星(阴线+十字+阳线)=底部反转；夜星(阳线+十字+阴线)=顶部反转。应用：十字星后一根K线方向=确认方向。",ImageType.CHART, listOf("孕线","Harami","十字星","晨星","夜星"), listOf("kline_001","kline_004","kline_005")),
        KnowledgeItem("ind_008","OBV能量潮",Category.INDICATORS,Level.INTERMEDIATE,
            "量在价先——OBV用成交量预判价格方向。",
            "OBV(On-Balance Volume)：OBV=前日OBV±当日成交量(涨+成交量,跌-成交量)。核心：量价配合=确认趋势,量价背离=反转前兆。价涨量增+OBV同步新高=多头健康。价涨OBV不涨=量价背离=上涨不可持续,可能回调。价跌OBV不跌或创新高=主力低位吸筹=底部信号。OBV突破前高=价格将跟随突破。OBV的绝对数值无意义,只看趋势方向。建议：OBV与MACD/均线配合使用,OBV先行转折=最强买入信号。",ImageType.CHART, listOf("OBV","能量潮","量价背离","成交量"), listOf("ind_002","ind_003","term_005")),
        KnowledgeItem("ind_009","BIAS乖离率与PSY心理线",Category.INDICATORS,Level.INTERMEDIATE,
            "涨多了要跌、跌多了要涨——乖离率量化了这个朴素道理。",
            "BIAS(乖离率)=(收盘价-N日均价)/N日均价×100%。正乖离过大=超买(短期>5%或>8%)→卖出。负乖离过大=超卖(短期<-5%或<-8%)→买入。参数：6日BIAS(短线)、12日(中线)、24日(长线)。关键：BIAS到了极值不代表马上反转(强势股可以一直超买)。PSY(心理线)=N日内上涨天数/N×100。PSY>75超买,PSY<25超卖。PSY在25-75间震荡=无趋势,适合高抛低吸。PSY背离：价创新低但PSY走高=底部信号。两者结合：BIAS极值+PSY区间确认=高胜率。",ImageType.FORMULA, listOf("乖离率","BIAS","PSY","心理线"), listOf("ind_001","kline_001","term_005")),
        KnowledgeItem("basic_013","分红送股与除权除息",Category.BASIC,Level.BEGINNER,
            "分红到底是不是白给的钱？除权除息全解析。",
            "现金分红(派息)：公司把利润以现金分给股东。除息日股价下调(除息价=前收盘-每股分红)。填权：股价涨回除息前价格(赚到分红)。贴权：股价没涨回来(分红白搭)。送股/转增：不发现金,增加股票数量。除权价=前收盘/(1+送股比例)。高送转(10送10以上曾是大题材,现已降温)。关键日期：股权登记日(持有才有分红)、除权除息日(股价调整)、分红到账日。红利税：持股<1月=20%、1月-1年=10%、>1年=0%。分红是长期投资回报的重要来源,但短线炒作分红毫无意义。",ImageType.FORMULA, listOf("分红","除权","除息","填权","送股"), listOf("basic_001","basic_009","basic_012")),
        KnowledgeItem("basic_014","融资融券入门",Category.BASIC,Level.INTERMEDIATE,
            "借钱买、借券卖——两融是放大收益也放大风险的双刃剑。",
            "融资(做多)：向券商借钱买股票,需50万资产开通。保证金比例100%=1:1杠杆(本金100万可买200万)。融资利息约6-8%/年,按日计息。维持担保比例<130%会被强制平仓。融券(做空)：借股票卖出,等跌了买回来还。券源有限(不是所有股票都能融券)。融券费用约8-10%/年。标的：主板/创业板多数可融资融券,科创板需更多资金。风险：杠杆放大亏损,极端行情可能穿仓(亏完本金还倒欠)。建议：新手远离两融,即使老手也应严格仓位管理。",ImageType.DIAGRAM, listOf("融资","融券","两融","杠杆","做空"), listOf("basic_001","strategy_003","risk_001")),
        KnowledgeItem("futures_017","跨品种与跨期套利",Category.FUTURES,Level.ADVANCED,
            "不赌方向也能赚钱——套利交易的稳定收益逻辑。",
            "跨期套利：同一品种不同月份合约价差交易。如螺纹05合约与10合约价差(正常为正,近低远高=正向市场)。当价差偏离历史均值→做多低价合约+做空高价合约→价差回归获利。跨品种套利：产业链相关品种价差。螺纹-铁矿(钢厂利润)=买铁矿+卖螺纹=做空利润。豆粕-豆油(压榨利润)=买大豆+卖豆粕豆油=做多压榨利润。豆粕-玉米(猪饲料价差)。跨市套利：同品种国内外价差(沪铜vs伦铜,关注汇率和运费)。套利优势：风险远低于单边,保证金更低。门槛：需多合约同时下单,对软件和速度要求高。",ImageType.DIAGRAM, listOf("套利","跨期","跨品种","价差","蝶式"), listOf("futures_001","futures_005","futures_010")),
        KnowledgeItem("futures_018","期货交割与逼仓",Category.FUTURES,Level.ADVANCED,
            "期货不是全部平仓了事的——交割月里的博弈。",
            "交割方式：实物交割(螺纹/豆粕等→仓单+现货)、现金交割(股指期货→按结算价现金结算)。个人户不能进入交割月(会被强平),机构可以。最后交易日：不同品种不同(一般为合约月份第10个交易日)。逼仓：多逼空(多头大量接货+空头无货可交→空头被迫高位平仓=价格暴涨)。空逼多(空头大量交货+多头没钱接货→多头低位平仓)。历史上著名的逼仓：1995国债327事件、2008原油逼仓、2022伦镍逼仓。防范：临近交割月轻仓、不重仓单一品种、关注仓单和持仓结构。",ImageType.DIAGRAM, listOf("交割","逼仓","仓单","最后交易日"), listOf("futures_001","futures_010","futures_015","futures_016")),
        KnowledgeItem("strategy_008","网格交易法",Category.STRATEGY,Level.INTERMEDIATE,
            "震荡市利器——机械化高抛低吸,适合上班族。",
            "网格交易：设定价格区间和网格间距,价格每跌一格买入一份、每涨一格卖出一份。参数：基准价(当前价)、网格间距(如每5%一格)、每格仓位(如总资金/20格=每格5%资金)。优点：不预测方向/震荡市稳定盈利/全自动/心理压力小。缺点：单边市(一路跌=不断买入仓位加重被套、一路涨=早早卖飞)是致命伤。改进：结合均线趋势过滤(均线上方只做多网格/下方只做空网格)。品种选择：波动大但不长期单向的ETF或宽基指数。最大回撤控制：预设底部价,跌破即暂停。",ImageType.FORMULA, listOf("网格交易","高抛低吸","震荡","机械交易"), listOf("strategy_001","risk_001","risk_006")),
        KnowledgeItem("strategy_009","海龟交易法则",Category.STRATEGY,Level.ADVANCED,
            "传奇交易员丹尼斯培养的海龟们——用一套简单规则持续盈利。",
            "核心思想：趋势跟踪,截断亏损让利润奔跑。入场：20日突破(创20日新高做多、创20日新低做空)。过滤：55日突破用于判断大趋势方向。仓位：每笔风险不超过总资金2%→仓位=总资金×2%/ATR(14)。止损：价格反向2×ATR止损。加仓：盈利后每0.5×ATR加仓一次,最多加4次(金字塔加仓)。出场：反向10日突破。精髓：胜率仅35-40%但盈亏比高达3:1以上,长期必然盈利。启示：交易系统的核心是坚持执行,而非追求高胜率。A股/期货均适用,只需调整参数适应波动率。",ImageType.FORMULA, listOf("海龟","趋势跟踪","ATR","突破","理查德丹尼斯"), listOf("strategy_001","strategy_003","risk_007")),
        KnowledgeItem("risk_006","凯利公式与仓位管理",Category.RISK,Level.ADVANCED,
            "数学告诉你每次该下多少注——凯利公式的最优仓位。",
            "凯利公式：f=(b×p-q)/b。f=最优仓位比例,b=盈亏比,p=胜率,q=1-p。示例：策略胜率40%、盈亏比3:1→f=(3×0.4-0.6)/3=0.2=20%仓位。简化版：半凯利=f/2=10%更稳妥。仓位管理原则：单笔最大亏损≤总资金2%(专业交易员铁律)。单品种最大仓位≤30%。总持仓仓位≤80%。仓位计算步骤：1.确定止损价→2.计算每股最大亏损→3.仓位=总资金×2%/每股亏损。不可梭哈(全仓一次)！连续亏损后减仓(亏损后缩小仓位)、连续盈利后可适当加仓。",ImageType.FORMULA, listOf("凯利公式","仓位管理","风险控制","头寸"), listOf("risk_001","risk_002","risk_003")),
        KnowledgeItem("risk_007","止损止盈体系",Category.RISK,Level.INTERMEDIATE,
            "会买的是徒弟会卖的是师傅——止损止盈定生死。",
            "止损类型：固定止损(如亏损5%无条件走)、技术止损(跌破支撑/均线/前低)、移动止损(价格上涨后止损上移锁定利润)、时间止损(持仓N天不涨就走)。ATR止损：止损价=入场价-2×ATR(14)(波动大放宽/波动小收紧)。最大回撤止损：从持仓最高点回撤X%即离场。止盈类型：固定止盈(如盈利10%走)、移动止盈(随价格上涨逐级上移)、分批止盈(到目标位卖1/3,再涨1/3,...)。盈亏比阈值：短线≥2:1、中线≥3:1。铁律：止损设了就坚决执行,绝不移动止损线！亏损加仓(摊平)是加速爆仓的最快路径。",ImageType.DIAGRAM, listOf("止损","止盈","移动止损","ATR"), listOf("risk_001","risk_003","risk_006")),
        KnowledgeItem("psych_004","交易心理常见偏差",Category.PSYCHOLOGY,Level.INTERMEDIATE,
            "你最大的敌人不是市场,是你自己的大脑——十大认知偏差。",
            "损失厌恶：亏损100元的痛苦>盈利150元的快乐→不止损死扛。锚定效应：买入价成为心理锚点→不回到成本不走。确认偏差：只找支持自己判断的信息→忽视反面证据。近因偏差：最近几笔交易影响判断→连续盈利=过度自信、连续亏损=不敢下单。处置效应：过早卖出盈利单(落袋为安)、过晚卖出亏损单(希望回本)。过度交易：不做就手痒→手续费吃掉利润。从众心理：大家都买我也买→顶部接盘。归因偏差：赚了是自己牛、亏了怪市场→无法进步。解决：写交易日志、量化规则、机械执行。",ImageType.NONE, listOf("心理偏差","损失厌恶","锚定","确认偏差"), listOf("psych_001","psych_002","psych_003")),
        KnowledgeItem("psych_005","交易日志与复盘",Category.PSYCHOLOGY,Level.BEGINNER,
            "每笔交易后写下为什么买为什么卖——这是从韭菜到老手的唯一捷径。",
            "交易日志必记：日期+品种+方向(多/空)+入场价+出场价+盈亏金额+入场理由(技术面/基本面/消息)+出场理由(止损/止盈/手动)+当时的情绪(贪婪/恐惧/犹豫)。每周复盘：胜率变化、平均盈亏比、最大回撤是否恶化、是否执行了计划(计划内亏损=好交易,计划外盈利=坏交易)。截图保存每笔交易的K线图标注进出场点。月度总结：本月错误Top3+改进措施。工具：Excel或Notion模板,飞书多维表格。坚持3个月你会发现自己的模式缺陷；坚持1年你会脱胎换骨。",ImageType.NONE, listOf("交易日志","复盘","总结","纪律"), listOf("psych_001","psych_003","strategy_009")),
        // ========== K线形态扩展 ==========
        KnowledgeItem("kline_011","乌云盖顶与刺透形态",Category.KLINE,Level.INTERMEDIATE,
            "两根K线定乾坤——乌云盖顶看跌,刺透形态看涨。",
            "乌云盖顶：上升趋势中,第一天大阳线,第二天高开低走大阴线,收盘深入第一天阳线实体的50%以上。确认：阴线放量+第三天低开不补=强烈看跌。刺透形态(旭日东升)：下降趋势中,第一天大阴线,第二天低开高走大阳线,收盘深入第一天阴线实体的50%以上。确认：阳线放量突破5日均线。刺透比看涨吞没更常见。注意：刺透不到50%视为反弹而非反转；乌云盖顶阴线收盘越深越可靠。",ImageType.CHART, listOf("乌云盖顶","刺透形态","旭日东升"), listOf("kline_001","kline_002","kline_004")),
        KnowledgeItem("kline_012","缺口理论",Category.KLINE,Level.INTERMEDIATE,
            "跳空缺口不是随便跳的——四种缺口的含义完全不同。",
            "普通缺口：无特别意义,几天内回补。突破缺口：带量跳空突破关键阻力/支撑,不回补=趋势确认。持续缺口(测量缺口)：趋势中途跳空,量度目标≈从突破缺口到持续缺口的距离再延伸等长。衰竭缺口：趋势末端跳空后迅速反转回补,是反转信号。岛形反转：衰竭缺口+横向整理+反向突破缺口=最强反转。缺口必补误区：突破缺口可能数年不补,衰竭缺口很快回补。实战：突破缺口出现后,等回踩缺口上沿不破=买入。",ImageType.CHART, listOf("缺口","跳空","突破缺口","衰竭缺口","岛形"), listOf("kline_003","kline_006","kline_008")),
        KnowledgeItem("kline_013","上升三法与下降三法",Category.KLINE,Level.INTERMEDIATE,
            "三法形态——主力洗盘后的方向确认。",
            "上升三法：大阳线后3-5根小阴线(缩量,不跌破阳线最低),最后再一根大阳线创新高=趋势延续看涨。下降三法：大阴线后3-5根小阳线(缩量,不涨破阴线最高),最后再一根大阴线创新低=趋势延续看跌。本质：主力在趋势中途洗盘,不破坏原有趋势结构。确认：中间K线必须缩量(主力没出货),最后突破必须放量。变体：两根而非三根调整K线也成立。区别：不要和三只乌鸦/红三兵混淆——三法形态中间K线实体小、不破前K线范围。",ImageType.CHART, listOf("上升三法","下降三法","持续形态","洗盘"), listOf("kline_003","kline_007","kline_009")),
        KnowledgeItem("kline_014","平头顶底与捉腰带线",Category.KLINE,Level.INTERMEDIATE,
            "同一价位反复出现——市场在用价格告诉你方向。",
            "平头顶：连续两根或多根K线最高价几乎相同(差<2跳),出现在涨势末端=多方无力再推高,看跌。平头底：最低价几乎相同,出现在跌势末端=空方砸不动,看涨。捉腰带线(光头光脚)：开盘即最高(阴线)或最低(阳线),无上影线。看跌捉腰带：光头阴线开盘=最高后一路跌,顶部信号。看涨捉腰带：光脚阳线开盘=最低后一路涨,底部信号。平头顶/底配合其他反转形态(吞没/孕线)确认率更高。核心：同一价位被反复触碰=该价位有强支撑/阻力。",ImageType.CHART, listOf("平头顶","平头底","捉腰带","光头光脚"), listOf("kline_001","kline_002","kline_010")),
        KnowledgeItem("kline_015","塔形顶与塔形底",Category.KLINE,Level.ADVANCED,
            "缓慢筑顶/底后快速反转——塔形形态的杀伤力。",
            "塔形顶：先是一连串小阳线缓慢推升→顶部几根小实体K线横盘(缩量)→突然一根或多根大阴线快速砸穿前期低点。特征：左边缓涨(诱多)、右边急跌(主力出货),中间缩量横盘=多空转换期。塔形底：缓跌→横盘缩量→大阳突破。塔形顶+放量砸=跌得猛(高位筹码全部套牢)。与头肩顶区别：塔形没有明确的左右肩,更像一个三角形或楔形顶。应对：塔形顶部横盘时减仓,跌破最右侧阳线低点务必离场。",ImageType.CHART, listOf("塔形顶","塔形底","慢涨快跌"), listOf("kline_004","kline_005","kline_008")),
        // ========== 技术指标扩展 ==========
        KnowledgeItem("ind_010","ADX/DMI趋向指标",Category.INDICATORS,Level.ADVANCED,
            "ADX不告诉你方向,只告诉你趋势强弱——这才是关键。",
            "DMI(趋向指标)由三条线组成：+DI(多方力量)、-DI(空方力量)、ADX(趋势强度)。+DI>-DI=多头主导,-DI>+DI=空头主导。ADX<20=无趋势(震荡市,适合高抛低吸)。ADX>25=趋势形成,ADX>40=强趋势,ADX>60=极端趋势(可能反转)。ADX向上+价格上升=强多头,ADX向上+价格下跌=强空头。ADX拐头向下=趋势减弱。关键用法：ADX在20以下横盘后突破20+价格突破区间=趋势启动信号。参数：常用14日。",ImageType.CHART, listOf("ADX","DMI","趋向指标","趋势强度"), listOf("ind_001","ind_002","ind_005")),
        KnowledgeItem("ind_011","布林带实战用法",Category.INDICATORS,Level.ADVANCED,
            "布林带不仅是超买超卖——带宽和形态透露更多信息。",
            "布林带=中轨(20日均线)±2倍标准差。常规：触下轨超卖买入、触上轨超买卖出。进阶1-带宽(BandWidth)：(上轨-下轨)/中轨,带宽缩窄到极致=即将变盘(横盘后出方向)。进阶2-％b指标：(收盘-下轨)/(上轨-下轨),>1突破上轨(强),<0跌破下轨(弱),在0.2-0.8震荡。进阶3-布林带方向：中轨向上+价格沿上轨走=强势(不轻易卖)；中轨走平=震荡高抛低吸。W底/M顶在布林带内的形态识别。双底(下轨+反弹+再探下轨不破)是极强买入信号。",ImageType.CHART, listOf("布林带","BOLL","带宽","%b"), listOf("ind_001","ind_005","kline_005")),
        KnowledgeItem("ind_012","一目均衡表",Category.INDICATORS,Level.ADVANCED,
            "日本交易员的独门绝技——一目均衡表五线合一的趋势系统。",
            "五条线：转换线(9日高低中值)、基准线(26日)、先行带A(转换线+基准线)/2前移26日、先行带B(52日)前移26日、迟行线(收盘后移26日)。云层=先行带A与B之间的区域。价格在云上=多头,云下=空头,云中=震荡。云层厚=支撑/阻力强。转换线上穿基准线=买入信号,下穿=卖出信号。迟行线在价格上方=多头,下方=空头。三线合一(转换线+基准线+迟行线汇聚)预示大行情。参数适用于日线,周线/月线同样有效。",ImageType.CHART, listOf("一目均衡","云图","转换线","基准线"), listOf("ind_001","ind_006","ind_008")),
        KnowledgeItem("ind_013","SAR抛物线指标",Category.INDICATORS,Level.BEGINNER,
            "SAR是唯一告诉你何时必须离场的指标——简单但致命。",
            "SAR(Stop and Reverse)：在K线图上以点状标示,在价格下方=持多,翻转到价格上方=转空。SAR从下方翻到上方=多单必须平仓。SAR从上方翻到下方=空单必须平仓。优点：明确的止损位/无歧义/适合趋势跟踪。缺点：震荡市中SAR频繁翻转导致反复止损(假信号)。优化：配合ADX过滤(ADX>25时才用SAR信号)。加速因子(AF)：起始0.02,每次创新高/新低+0.02,上限0.2,AF越大SAR越紧贴价格。初始AF调小降低噪声。",ImageType.CHART, listOf("SAR","抛物线","止损","转向"), listOf("ind_001","ind_010","risk_007")),
        KnowledgeItem("ind_014","VWAP与MFI",Category.INDICATORS,Level.ADVANCED,
            "机构用VWAP衡量成交均价,MFI是加入了成交量的RSI——两者互补。",
            "VWAP(成交量加权均价)=∑(价格×成交量)/∑成交量,日内不断更新。意义：机构大单的成交均价,价格高于VWAP=多头占优/低于=空头占优。VWAP支撑/阻力：回调到VWAP止跌=强、跌破VWAP止涨=弱。MFI(资金流量指标)：类似RSI但加入成交量权重。计算：典型价=(高+低+收)/3,资金流=典型价×成交量,正负资金流比率转0-100。MFI>80超买,MFI<20超卖。MFI与价格背离：价格新高MFI不新高=反转信号(比RSI背离更可靠)。参数常用14日。",ImageType.FORMULA, listOf("VWAP","MFI","成交量加权","资金流"), listOf("ind_002","ind_004","ind_008")),
        KnowledgeItem("ind_015","阿隆指标Aroon",Category.INDICATORS,Level.INTERMEDIATE,
            "Aroon告诉你新高/新低出现在多久前——衡量趋势的新视角。",
            "Aroon-Up=100×(N-距N日内最高点的天数)/N。Aroon-Down=100×(N-距N日内最低点的天数)/N。数值0-100。Aroon-Up>70且Aroon-Down<30=上升趋势。Aroon-Down>70且Aroon-Up<30=下降趋势。两者都<50=震荡/无趋势。两者同时>70=极强双向波动(罕见)。Aroon-Up上穿Aroon-Down=买入,下穿=卖出。优势：比均线更灵敏,先于价格反应趋势变化。参数：常用25日(中短线)或14日(短线)。建议搭配MACD确认。",ImageType.CHART, listOf("Aroon","阿隆","趋势检测","新高新低"), listOf("ind_001","ind_002","ind_010")),
        // ========== 基础入门扩展 ==========
        KnowledgeItem("basic_015","IPO打新攻略",Category.BASIC,Level.BEGINNER,
            "A股打新是普通人最稳的低风险套利——但规则变了。",
            "A股打新：市值配售制,沪市/深市各1万市值=1个配号。主板新股上市首日涨跌幅44%,之后10%。注册制后：科创板/创业板前5日无涨跌幅限制,破发风险大幅上升(以前闭眼打新稳赚的时代结束了)。北交所打新需100万资产。策略：有选择地打(看发行市盈率vs行业市盈率,低于行业=安全垫厚)。中签后：主板新股首日一般不卖等连板,注册制新股首日择机卖出。可转债打新：无市值要求,中签1000元,上市溢价约10-30%。",ImageType.FORMULA, listOf("打新","IPO","中签","破发","新股"), listOf("basic_001","basic_012")),
        KnowledgeItem("basic_016","股票估值方法",Category.BASIC,Level.ADVANCED,
            "PE、PB、PS、DCF——四种估值法,各适用于不同公司。",
            "PE(市盈率)=股价/每股收益。适用：盈利稳定的成熟公司。银行/消费PE<15低估,科技/成长PE 30-50正常,亏损公司PE无效。PB(市净率)=股价/每股净资产。适用：银行/券商/周期股(重资产),PB<1破净可能低估。PS(市销率)=市值/营收。适用：高成长亏损公司(早期科技/生物医药),PS<3合理。PEG=PE/盈利增长率,<1低估。DCF(现金流折现)：预测未来现金流并折现,理论上最精确但假设多。ROE>15%=好公司。估值不是精确科学,模糊的正确胜过精确的错误。",ImageType.FORMULA, listOf("PE","PB","估值","DCF","PEG"), listOf("basic_001","basic_009","basic_010")),
        KnowledgeItem("basic_017","A股交易规则",Category.BASIC,Level.BEGINNER,
            "T+1、涨跌停、手续费——入市必知的游戏规则。",
            "T+1：当天买入次日才能卖出(ETF/可转债T+0)。涨跌停：主板±10%/ST股±5%/创业板科创板±20%/北交所±30%/新股前5日无限制。手续费：佣金万2.5以下(华泰/东财更低)、印花税0.05%(卖出单边)、过户费0.001%。每笔最低佣金5元=小额交易不划算。集合竞价：9:15-9:25(可挂可撤9:20前),9:25产生开盘价。大宗交易：单笔>30万股/200万元,折价/溢价成交。盘后固定价交易(科创板/创业板15:05-15:30)。除权除息日股价自动调整。",ImageType.NONE, listOf("T+1","涨跌停","手续费","集合竞价"), listOf("basic_001","basic_013","basic_014")),
        KnowledgeItem("basic_018","美股投资入门",Category.BASIC,Level.INTERMEDIATE,
            "全球最大市场——美股交易规则、开户与核心指数。",
            "开户：盈透(IBKR)/嘉信/富途moomoo等。入金：境外银行卡或港卡。交易时间：美东9:30-16:00(对应北京时间夏令21:30-4:00,冬令22:30-5:00),盘前4:00-9:30盘后16:00-20:00。T+2交收、T+0交易(日内可买卖无限制)。无涨跌停但有熔断(标普跌7%/13%/20%暂停交易)。最小交易1股(非A股的100股/手)。核心指数：道指(30只蓝筹)、标普500(500只大盘)、纳指(科技为主)。重要个股：AAPL/MSFT/NVDA/GOOG/AMZN/META/TSLA七巨头。财报季：每季度,股价波动大。",ImageType.NONE, listOf("美股","纳斯达克","标普","道琼斯"), listOf("basic_001","macro_002","macro_003")),
        KnowledgeItem("basic_019","港股投资入门",Category.BASIC,Level.INTERMEDIATE,
            "港股通、恒生指数、港股特色——去港股前的必修课。",
            "港股通：通过A股账户买港股,门槛50万。南向资金净流入=利好,净流出=偏空。交易时间：9:30-12:00,13:00-16:00(T+0交易,T+2交收)。无涨跌停。恒生指数(HSI)：港股标杆,成分股82只。恒生科技：ATMJ(阿里腾讯美团京东)+小米快手等。港股特色：老千股(反复合股供股坑人)、仙股(<1港元)、高股息国企。AH股溢价：同一公司A股通常比H股贵20-40%(流动性溢价)。打新：现金/融资认购,上市首日可卖出无限制。印花税0.1%(买卖双边)。",ImageType.NONE, listOf("港股","港股通","恒生指数","AH溢价"), listOf("basic_001","basic_018","macro_003")),
        KnowledgeItem("basic_020","集合竞价机制",Category.BASIC,Level.INTERMEDIATE,
            "9:15-9:25这10分钟是主力表演时间——看懂竞价不吃亏。",
            "9:15-9:20：可挂单可撤单,主力经常挂大单拉高/压低后撤单制造假象(试盘)。9:20-9:25：可挂单不可撤单,这5分钟的量才是真实意图。9:25：产生开盘价(最大成交量原则)。尾盘集合竞价(14:57-15:00深市,沪市仅收盘前最后3分钟)：决定收盘价。竞价量比=竞价成交量/过去5日均量,>5%较活跃。竞价高开3%以上+竞价量比>10%+板块强势=可能涨停。竞价低开且量比大=恐慌抛售。首笔成交方向：第一笔是买盘还是卖盘往往决定当日多空。",ImageType.NONE, listOf("集合竞价","开盘价","试盘","量比"), listOf("basic_001","basic_017","strategy_005")),
        // ========== K线补充(续) ==========
        KnowledgeItem("kline_016","反转日与关键K线",Category.KLINE,Level.ADVANCED,
            "单日反转、两极反转——一根K线可以改变整个趋势。",
            "单日反转：创新高后当日大幅收低(顶部反转日)或创新低后大幅收高(底部反转日),同日完成突破与回破。特征：开盘冲高→回落收低(上影线很长),放巨量。关键反转日需3-5天确认(后续不创新高/低)。纺锤线：实体极小+上下影线=多空僵持,方向待决。大敌当前(Advance Block)：三根阳线但实体越来越小+上影越来越长=多头衰竭(与红三兵区别)。执带形态：大阳/大阴直接突破均线组合,强势信号。关键K线需结合位置：低位的大阳和高位的大阴意义完全不同。",ImageType.CHART, listOf("反转日","关键K线","纺锤线","实体衰竭"), listOf("kline_001","kline_004","kline_009")),
        KnowledgeItem("kline_017","成交量与K线配合",Category.KLINE,Level.INTERMEDIATE,
            "K线是骨架成交量是血肉——没有量的配合形态就是空壳。",
            "量价八法：1.价涨量增=正常多头(持有)。2.价涨量缩=多头乏力(减仓)。3.价跌量增=空头强(出)。4.价跌量缩=正常回调(观望)。5.天量天价(量创历史+价创高)=可能见顶。6.地量地价(缩到极致+止跌)=可能见底。7.放量突破+不回踩=真突破。8.无量突破=假突破。缩量上涨(惜售)=强势,但持续缩量上涨=危险。底部放量+中大阳=吸筹信号。顶部放量+长上影=出货信号。VWAP+成交量配合验证分时走势。",ImageType.CHART, listOf("量价","成交量","天量","地量","放量"), listOf("kline_001","kline_002","ind_008")),
        KnowledgeItem("kline_018","多周期K线共振",Category.KLINE,Level.ADVANCED,
            "日线看趋势、4小时定方向、1小时找入场——多周期共振法。",
            "三级周期：大周期(周/日)=定趋势方向,中周期(4h/1h)=找交易机会,小周期(15min/5min)=精确入场。共振条件：三个周期指向同一方向=最高胜率。大小周期背离：日线下跌但4H金叉=可能反弹,但反弹后大概率继续下跌(大周期为王)。多周期形态：日线头肩底+4H突破颈线+1H回调不破=最佳买点。各级别支撑阻力叠加处=强支撑/阻力。不同品种适合不同周期(期货短线用15min-1h,股票中线用日-周)。切忌只看小周期忘了大方向。",ImageType.CHART, listOf("多周期","共振","时间框架","波段"), listOf("kline_004","strategy_016","strategy_018")),
        // ========== 期货专题扩展 ==========
        KnowledgeItem("futures_019","期货合约规格大全",Category.FUTURES,Level.INTERMEDIATE,
            "每个品种一手多少钱、保证金多少——实用速查。",
            "螺纹钢(RB)：10吨/手,保证金约4000-6000元,手续费万1。铁矿石(I)：100吨/手,保证金约1-1.5万。焦炭(J)：100吨/手,保证金约3万。豆粕(M)：10吨/手,保证金约3000元,最便宜品种之一。原油(SC)：1000桶/手,保证金约8-10万(门槛高)。PTA：5吨/手,保证金约3000元。纯碱(SA)：20吨/手,保证金约6000元。甲醇(MA)：10吨/手,保证金约3000元。沪铜(CU)：5吨/手,保证金约4万。黄金(AU)：1000克/手,保证金约5万。股指IF：每点300元,保证金约15万(最贵)。生猪(LH)：16吨/手,保证金约4万。一手价值=合约乘数×价格×保证金比例。",ImageType.NONE, listOf("合约规格","保证金","一手","乘数"), listOf("futures_001","futures_005","futures_020")),
        KnowledgeItem("futures_020","期货保证金制度",Category.FUTURES,Level.INTERMEDIATE,
            "保证金不是手续费——理解保证金制度才能控制风险。",
            "保证金=合约价值×保证金比例(交易所标准+期货公司加收2-5%)。杠杆=1/保证金比例(10%保证金=10倍杠杆)。当日盈亏直接增减保证金。可用资金<0=需追加保证金(追保)。风险度=持仓保证金/权益×100%,>100%会被强平。盘中强平线：通常风险度>100%时期货公司电话通知,不补就强平。隔夜保证金高于日内(约1.5倍)=隔夜跳空风险更大。长假前交易所普遍提保(防外盘剧烈波动)。技巧：只用一半可用资金、留足30%以上缓冲、长假前减仓或清仓。",ImageType.FORMULA, listOf("保证金","杠杆","强平","追保"), listOf("futures_001","futures_004","risk_001")),
        KnowledgeItem("futures_021","中国五大期货交易所",Category.FUTURES,Level.BEGINNER,
            "上期所/大商所/郑商所/中金所/能源中心——各管哪些品种。",
            "上海期货交易所(SHFE)：螺纹/热卷/铜/铝/锌/铅/镍/锡/黄金/白银/橡胶/沥青/纸浆。大连商品交易所(DCE)：铁矿石/焦煤/焦炭/豆粕/豆油/豆一/玉米/生猪/鸡蛋/塑料/PP/PVC/乙二醇/苯乙烯/纤维板。郑州商品交易所(ZCE)：PTA/甲醇/纯碱/玻璃/尿素/白糖/棉花/菜粕/花生/苹果/红枣/短纤。中金所(CFFEX)：沪深300IF/中证500IC/上证50IH/中证1000IM/2/5/10/30年国债期货。上海能源中心(INE)：原油/20号胶/国际铜/低硫燃油/集运指数(欧线)。",ImageType.NONE, listOf("交易所","上期所","大商所","郑商所","中金所"), listOf("futures_001","futures_005","futures_019")),
        KnowledgeItem("futures_022","股指期货实战",Category.FUTURES,Level.ADVANCED,
            "IF、IC、IM、IH——期指不仅是对冲工具更是领先指标。",
            "IF(沪深300)：大蓝筹代表,每点300元,保证金约15万。IC(中证500)：中盘股,每点200元,保证金约15万。IM(中证1000)：小盘股,每点200元。IH(上证50)：超大盘。期指与现货关系：期货通常领先现货3-5分钟(期指先跌预示大盘将跌)。升贴水：期货>现货=升水(多头气氛浓),期货<现货=贴水(偏空)。贴水较大时买入期指+做空ETF可套利(但门槛高)。IC长期贴水=中证500弱势。交割日(每月第三个周五)波动加大。策略：对冲(持有股票+做空期指锁仓),或纯方向交易。",ImageType.DIAGRAM, listOf("股指期货","IF","IC","IH","升贴水"), listOf("futures_001","futures_017","strategy_017")),
        KnowledgeItem("futures_023","国债期货入门",Category.FUTURES,Level.ADVANCED,
            "利率期货——债券市场的风向标。",
            "2年期TS/5年期TF/10年期T/30年期TL国债期货。每手面值：2年200万/5年100万/10年100万/30年100万。最小变动价位0.005元。国债期货价格与利率反向：利率降→国债涨(做多),利率升→国债跌(做空)。影响因素：央行MLF/LPR调整、CPI、GDP、地方债发行节奏。基差交易：国债期货vs现货(CTD券)的价差。跨期套利：近远月合约价差。国债期货波动相对小,但30年期(超长端)波动加大。适合：宏观对冲、债券组合套保、利率方向交易。",ImageType.NONE, listOf("国债期货","利率","TS","TF","T"), listOf("futures_001","macro_002","futures_022")),
        KnowledgeItem("futures_024","期权进阶：铁鹰与蝶式",Category.FUTURES,Level.ADVANCED,
            "四大策略之外的进阶玩法——赚时间价值和波动率。",
            "铁鹰(Iron Condor)：卖出虚值看涨+买入更虚值看涨(熊市价差)+卖出虚值看跌+买入更虚值看跌(牛市价差)。四腿组合,赚时间价值+标的在区间内波动。适用：预期标的窄幅震荡。蝶式(Butterfly)：买入一张虚值Call+卖两张平值Call+买一张虚值Call(对称),或Put版。赚标的不动+时间衰减。日历价差(Calendar Spread)：卖近月+买远月同执行价,赚时间衰减差异(近月贬值更快)。跨式突破(Straddle/Strangle)：买Call+Put,赌大幅波动。策略选择核心：看对方向+选对策略组合。",ImageType.DIAGRAM, listOf("铁鹰","蝶式","日历价差","跨式"), listOf("options_001","options_002","options_003")),
        KnowledgeItem("futures_025","期权希腊字母详解",Category.FUTURES,Level.ADVANCED,
            "Delta/Gamma/Theta/Vega/Rho——五大希腊字母掌控期权风险。",
            "Delta：标的涨1元期权涨Delta元。Call Delta 0-1,Put Delta -1-0。平值≈0.5/-0.5。Gamma：Delta的变化速度,平值最大=Gamma风险最高。Theta：时间衰减,每天亏多少(买方每天亏Theta、卖方每天赚Theta)。末日轮Theta加速(最后几天时间价值暴跌)。Vega：波动率变化影响,IV(隐含波动率)升1%=期权涨Vega。恐慌时IV飙升利好买方,平静时IV回落利好卖方。Rho：利率影响(对短期期权影响极小可忽略)。组合希腊：多腿策略需算净Delta=方向敞口。",ImageType.FORMULA, listOf("Delta","Gamma","Theta","Vega","希腊字母"), listOf("options_001","options_003","futures_024")),
        KnowledgeItem("futures_026","期货程序化交易",Category.FUTURES,Level.ADVANCED,
            "用代码代替人判断——期货量化的入门路径。",
            "平台选择：文华财经WH8(付费/简单/云端)、交易开拓者TB(专业/麦语言)、VNPy(免费/Python开源/需要编程基础)、聚宽(股票为主)。回测要点：滑点(市价单设2跳滑点)、手续费(双边计算)、主力合约切换(复权连续)。简单策略：双均线金叉死叉(10/20线)、布林带突破、海龟突破、RSI超买超卖。注意：过拟合(参数调得太精准回测很好看实盘一塌糊涂)、未来函数(用了未来数据)。风控代码：最大持仓限制、单日最大亏损停机、定时清仓(收盘前5分钟)。模拟盘至少跑3个月再上实盘。",ImageType.DIAGRAM, listOf("程序化","量化","自动化","Python"), listOf("futures_001","strategy_007","strategy_009")),
        KnowledgeItem("futures_027","CFTC持仓分析",Category.FUTURES,Level.ADVANCED,
            "跟着聪明钱走——美国CFTC持仓报告的解读方法。",
            "CFTC每周五公布(截至周二),含：商业持仓(生产商/贸易商套保)、非商业(基金/投机大户)、非报告(散户)。商业套保净空=生产商在卖(正常套保,不一定看空)。非商业净多头寸增加=基金做多=看涨。非商业净空增加=看跌。净多仓位极值(历史新高)=过度拥挤,可能反转。关注品种：黄金/白银/原油/铜/大豆/玉米/豆粕(内外联动强)。总持仓量增加+价格涨=趋势健康,总持仓减少+价格涨=后劲不足。国内用CFFEX/CZCE/DCE/SHFE的会员持仓排名替代(前20席位)。",ImageType.DIAGRAM, listOf("CFTC","持仓报告","COT","基金"), listOf("futures_004","futures_005","macro_003")),
        KnowledgeItem("futures_028","点价与基差贸易",Category.FUTURES,Level.ADVANCED,
            "现货贸易的高级玩法——用期货点价实现最优采购。",
            "点价：买卖双方约定以\"期货价+固定升贴水\"作为最终成交价,买方可在约定期限内选择任一日货价(点价)。例如：买豆粕=豆粕期货05合约+100元/吨,买方择机在05合约2800时点价→成交价2900。卖方通过期货套保锁定利润。基差合同：约定基差(现货-期货价差)而非绝对价,到约定日期按盘面价结算。点价策略：买方希望在期货回调时点价,卖方反之。点价窗口通常1-3个月。产业客户必会技能。",ImageType.DIAGRAM, listOf("点价","基差贸易","升贴水","定价"), listOf("futures_001","futures_010","futures_016")),
        // ========== 策略专题扩展 ==========
        KnowledgeItem("strategy_010","双均线交易系统",Category.STRATEGY,Level.INTERMEDIATE,
            "所有策略的起点——双均线金叉死叉,简单但不简陋。",
            "参数选择：5/20(短线)、10/30(中线)、20/60(长线)。金叉(快线上穿慢线)=买入,死叉(快线下穿慢线)=卖出。优化1：金叉+价格在均线上方+均线方向向上=确认。优化2：死叉但均线方向向上=回调而非反转,不卖。优化3：金叉但均线向下=反弹而非反转,不买。均线参数选择适合自己的风格(交易次数/盈亏比)。双均线弊端：震荡市反复止损(建议加ADX过滤,ADX<20不交易)。止盈：死叉出场或目标位(前高/前低)。移动止损：沿均线移动。",ImageType.CHART, listOf("双均线","金叉","死叉","均线策略"), listOf("strategy_001","ind_001","strategy_009")),
        KnowledgeItem("strategy_011","突破交易法",Category.STRATEGY,Level.INTERMEDIATE,
            "横有多长竖有多高——突破交易是趋势跟踪的核心。",
            "突破定义：价格突破前N日最高/最低。水平突破：突破横盘箱体上沿/下沿。趋势线突破：突破下降趋势线(做多)或上升趋势线(做空)。确认三要素：1.收盘价突破(盘中突破不确认) 2.放量(>过去5日均量1.5倍) 3.突破后不回踩突破点(或回踩不破)。假突破识别：突破当天冲高回落留长影、缩量突破、次日即回破。突破入场方式：突破当时追入(激进)、等回踩不破再入(稳健)。目标=横盘宽度(箱体高度)向上翻1倍。止损：设在箱体下沿下方。",ImageType.CHART, listOf("突破","横盘","箱体","假突破"), listOf("strategy_003","strategy_004","kline_003")),
        KnowledgeItem("strategy_012","均值回归策略",Category.STRATEGY,Level.ADVANCED,
            "价格不会永远偏离均值——做回归是震荡市的圣杯。",
            "均值回归(Mean Reversion)：价格偏离均线/布林带后,有回归均值的倾向。指标：布林带外轨(>2σ)回归中轨、RSI<30或>70反转。配对交易(Pairs Trading)：两只高度相关的股票价差扩大时做回归(买弱卖强等收敛)。可转债正股联动回归。注意事项：强势股可以一直偏离均值(别逆势加仓)。止损必设：回归失败(继续沿趋势突破)的概率不小。回归策略在震荡市表现好,趋势市亏损。参数：布林带(20,2)±触碰外轨后回归中轨止盈、RSI>70开空<30开多。",ImageType.CHART, listOf("均值回归","回归","配对交易","震荡策略"), listOf("strategy_001","strategy_008","ind_011")),
        KnowledgeItem("strategy_013","动量交易策略",Category.STRATEGY,Level.ADVANCED,
            "强者恒强弱者恒弱——动量策略的核心逻辑。",
            "动量因子：过去N日涨幅最大的品种继续涨的概率大于反转。买入过去20/60/120日涨幅前10%的品种,定期(每月)换仓。A股中证500/创业板动量效应显著。双动量：绝对动量(正收益持有负收益空仓)+相对动量(买最强卖最弱)。注意：动量策略最怕趋势反转(风格切换时大跌)。风控：加入均线过滤器(只在均线上方持多),分批建仓。期货动量：每日计算N品种的N日涨跌,做多最强3-5个、做空最弱3-5个(多空组合)。CS(时间序列动量)：同一品种比较不同周期的动量。",ImageType.FORMULA, listOf("动量","强者恒强","换仓","因子"), listOf("strategy_001","strategy_009","strategy_014")),
        KnowledgeItem("strategy_014","配对交易与协整",Category.STRATEGY,Level.ADVANCED,
            "找到两只走势相似的品种做价差回归——统计套利核心。",
            "配对交易前提：两个品种存在长期稳定的价差关系(协整)。候选：同一板块(银行vs券商)/跨市场AH/(期货)豆油vs棕榈油/螺纹vs热卷/(ETF)沪深300vs中证500。步骤：1.计算价差(价格比或对数价差) 2.标准化(Z-Score) 3.当Z>2做空价差(买弱卖强),Z<-2做多价差,回归0平仓。风险：协整关系可能破裂(基本面改变)/极端行情价差持续扩大(俄罗斯事件等冲击)。风控：单次配对最大亏损控制。工具：Python(statsmodels协整检验)+聚宽/米筐回测平台。",ImageType.FORMULA, listOf("配对交易","协整","价差","统计套利"), listOf("strategy_012","strategy_013","futures_017")),
        KnowledgeItem("strategy_015","事件驱动策略",Category.STRATEGY,Level.INTERMEDIATE,
            "财报、重组、分红——重大事件前后如何布局。",
            "财报季策略：预期财报超预期→提前3-5天买入,财报发布后利好兑现卖出(买预期卖事实)。业绩预告超预期+低位=持续性更强。年报高送转(已降温)。重组/并购：明确公告后往往一字板买不到,提前布局需内幕(非法)。ST摘帽：年报扭亏后申请摘帽,摘帽前1-2月介入。重大合同/中标公告：当日买入短线博弈。分红除权前买入等填权?不靠谱——红利税+股价除权=无套利。事件驱动本质是信息博弈,散户信息落后机构太多。建议只参与财报预告类确定性较高的事件。",ImageType.NONE, listOf("事件驱动","财报","重组","摘帽"), listOf("strategy_003","basic_009","basic_013")),
        KnowledgeItem("strategy_016","波段交易法",Category.STRATEGY,Level.INTERMEDIATE,
            "不做超短线不搞长线——波段吃鱼身,持仓3-15天。",
            "波段：识别一个完整的涨跌/跌涨周期,在转折点介入,持仓几天到两周。入场信号：回调/反弹+金叉/死叉+放量=启动。上升波段做多,下降波段做空(期货)。上升波段三段：1.底部放量突破(建仓) 2.主升浪(加仓/持有) 3.高位放量滞涨(减仓)。回调比例：斐波那契38.2%/50%/61.8%,50%回调不破=加仓点。日内不做波段(波动不够)。止损：前低下方,止盈：前高或测量目标。最佳级别：60min/日线。适合：不能盯盘的上班族(日线级别波段)。",ImageType.CHART, listOf("波段交易","鱼身","持仓","斐波那契"), listOf("strategy_001","strategy_003","kline_018")),
        KnowledgeItem("strategy_017","日内交易与短线",Category.STRATEGY,Level.ADVANCED,
            "高频不等于高收益——日内交易的纪律与技巧。",
            "日内三大铁律：1.当天必须平仓(不隔夜) 2.单日止损额(如总资金1%)到达即停 3.只交易流动性最好的品种(螺纹/甲醇/豆粕/PTA)。日内时段：9:00-9:30开盘波动最大→顺势跟进；10:00-11:00趋势延续或反转；11:00-11:30波动减小；13:30-14:30下午趋势；14:30-15:00尾盘加速。盘口技巧：看买卖挂单厚度、大单成交方向、盘口吃单速度。日内的关键是判断当天是多头日还是空头日：高开高走不破分时均线=多头日做多为主。手续费：日内高频手续费是巨大成本(万1双边每天几十笔=手续费吃掉利润)。",ImageType.CHART, listOf("日内交易","短线","高频","盘口"), listOf("strategy_001","strategy_016","risk_007")),
        KnowledgeItem("strategy_018","多时间框架分析",Category.STRATEGY,Level.ADVANCED,
            "日线看大势、4H定方向、1H找形态、15min精确入场",
            "四层时间框架体系：宏观层(周线/月线)=判断大趋势和关键支撑阻力。策略层(日线)=确定交易方向和主要形态。执行层(4H/1H)=识别入场形态和信号。精确层(15min/5min)=寻找最优入场点和止损位。原则：1.高一层框架决定方向(日线多头则4H以下只做多) 2.同一方向多周期共振=最佳 3.大周期支撑/阻力>小周期 4.从大到小逐级分析。经典模式：周线上升趋势+日线回调到支撑+4H出现刺透形态+1H MACD金叉=入场。切忌小周期逆大趋势。",ImageType.CHART, listOf("多周期","时间框架","共振","级别"), listOf("strategy_001","strategy_016","kline_018")),
        KnowledgeItem("strategy_019","支撑阻力交易法",Category.STRATEGY,Level.INTERMEDIATE,
            "所有技术分析的落脚点都是支撑和阻力——找到这两条线就成功了一半。",
            "支撑/阻力识别：1.前高/前低 2.均线(20/60/120) 3.布林带上下轨 4.趋势线 5.斐波那契回撤 6.整数关口(如3000点) 7.成交密集区。多个支撑/阻力汇聚=更强。交易：触及支撑做多(止损下方)、触及阻力做空(止损上方)。突破阻力变支撑、跌破支撑变阻力(角色互换)。假突破：突破后收盘未站稳=回到区间。推荐方法：在明显支撑/阻力位挂限价单(Buy Limit/Sell Limit),而非追突破(安全边际更高)。支撑阻力不一定精确到点位,看区域而非一条线。",ImageType.CHART, listOf("支撑","阻力","前高","前低","趋势线"), listOf("strategy_001","strategy_011","kline_001")),
        // ========== 策略补充(续) ==========
        KnowledgeItem("strategy_020","布林带交易策略",Category.STRATEGY,Level.INTERMEDIATE,
            "布林带三招——从简单触碰回归到带宽爆炸。",
            "策略一(回归)：价格触碰下轨+RSI<30→做多,目标中轨,止损下轨下方。价格触碰上轨+RSI>70→做空,目标中轨。策略二(带宽收缩)：带宽缩至6个月低点+价格横盘→布林带即将扩张,挂突破单(上破做多下破做空)。策略三(沿轨行走)：价格沿上轨走+中轨向上→强势趋势,不逆势做空,等回到中轨再做多。策略四(%b背离)：价格创新高但%b不创新高→背离看跌,反之看涨。所有策略必须等K线收盘确认,盘中假信号多。",ImageType.CHART, listOf("布林带","BOLL策略","带宽收缩","%b"), listOf("strategy_001","ind_011","strategy_012")),
        KnowledgeItem("strategy_021","RSI背离交易法",Category.STRATEGY,Level.INTERMEDIATE,
            "RSI背离是最可靠的逆转信号——学会这招胜率提升显著。",
            "顶背离：价格创新高但RSI未创新高(RSI走低)=上涨动能衰竭,即将下跌。底背离：价格创新低但RSI未创新低(RSI走高)=下跌动能衰竭,即将上涨。确认：背离后等K线反转形态(吞没/刺透/黄昏星)再入场。隐藏背离：价格未创新高但RSI创新高(趋势延续)、价格未创新低但RSI创新低(趋势延续)。多周期共振：日线+4H同时背离=强信号。RSI数值：背离+RSI在超买/超卖区(>70或<30)=更强。止损设在背离K线的高/低点外。",ImageType.CHART, listOf("RSI","背离","顶背离","底背离"), listOf("strategy_001","ind_002","strategy_019")),
        // ========== 风控专题 ==========
        KnowledgeItem("risk_008","VaR风险价值",Category.RISK,Level.ADVANCED,
            "VaR在95%置信度下一天最多亏多少——量化风险管理的第一步。",
            "VaR(Value at Risk)=在给定置信度和持有期内的最大可能损失。历史模拟法：取过去250日每日收益率排序,第5%分位的亏损=95%置信度VaR。参数法：VaR=仓位价值×日波动率×1.65(95%置信)。蒙特卡洛模拟：用随机路径模拟未来分布。局限：VaR假设正态分布但实际是肥尾(极端事件发生概率远超正态分布预测)。CVaR(条件VaR)：超过VaR的平均损失,更保守。建议：日常用VaR做仓位上限参考(单日VaR不超过总资金3%),极端行情时VCaR约束。",ImageType.FORMULA, listOf("VaR","风险价值","CVaR","蒙特卡洛"), listOf("risk_001","risk_003","risk_006")),
        KnowledgeItem("risk_009","最大回撤与恢复",Category.RISK,Level.INTERMEDIATE,
            "回撤10%需要涨11%回本,回撤50%需要涨100%——回撤是复利的死敌。",
            "回撤40%=需涨67%回本,回撤50%=需涨100%,回撤80%=需涨400%。这就是为什么不能大亏！最大回撤(MDD)：资金曲线从峰值到谷底的最大跌幅。回撤恢复时间：回撤30%可能需3-6个月恢复,回撤50%可能需1-2年。控制：1.单笔最大亏损≤2%→连续亏10笔才亏20% 2.亏损后缩小仓位(每亏5%仓位减半) 3.回撤超20%强制停手两周反思。恢复期间心态：不要急于翻本(越急越亏),降低仓位慢慢积累小盈利重建信心。",ImageType.FORMULA, listOf("最大回撤","恢复","MDD","回本"), listOf("risk_001","risk_002","risk_007")),
        KnowledgeItem("risk_010","相关性风险管理",Category.RISK,Level.ADVANCED,
            "你以为分散了风险,结果全在同一个方向——相关性陷阱。",
            "高相关性品种同时持多=集中风险(如螺纹+热卷+铁矿=做多黑色产业链)。低/负相关性组合才是真正的分散。常见高相关：螺纹/热卷(>0.9)、豆油/棕榈油(>0.8)、IF/IH(>0.9)、黄金/白银(>0.7)。负相关：美元/黄金(-0.5)、股票/国债(股债跷跷板)。计算：用Excel CORREL函数计算过去60日收益率相关性。原则：持仓品种间相关性<0.5才算分散。按板块/产业链设定总敞口上限(黑色系总仓位<50%)。避免同时做多所有高相关品种。",ImageType.FORMULA, listOf("相关性","分散","集中风险","相关系数"), listOf("risk_001","risk_003","risk_006")),
        KnowledgeItem("risk_011","压力测试与情景分析",Category.RISK,Level.ADVANCED,
            "如果明天再来一次2020年3月或2015年股灾,你的账户会怎样？",
            "压力测试：假设极端行情,计算账户盈亏。历史情景：2020年3月(原油暴跌+美股四次熔断)、2015年6月(股灾千股跌停)、2016年1月(熔断)、2008年次贷危机。自设情景：大盘跌10%/螺纹跌5%+铁矿石跌7%/豆粕涨跌停等。持仓在多情景下都存活=安全。缺口风险：跳空(如长假后)无法止损,实际亏损远超止损线。应对：长假前减仓至30%以下或清仓、重大事件前减仓(非农/议息/USDA)、多品种间设置总体最大亏损限额。",ImageType.NONE, listOf("压力测试","情景分析","极端行情","跳空"), listOf("risk_001","risk_003","risk_008")),
        KnowledgeItem("risk_012","黑天鹅与肥尾风险",Category.RISK,Level.ADVANCED,
            "塔勒布说黑天鹅无法预测但可以预防——如何不让自己被一次极端事件消灭。",
            "肥尾分布：真实市场收益率并非正态分布,极端事件(±5σ)概率远高于理论值。黑天鹅事件特征：不可预测、影响极大、事后合理化。经典案例：2008金融危机、2015瑞郎黑天鹅(瞬间涨30%无数账户穿仓)、2020原油负价格、2022伦镍逼空。杠铃策略：90%资金极度安全(国债/货基)+10%资金做高风险高回报交易,最坏情况只亏10%。永不做空波动率(卖出期权无限风险)。不重仓流动性差的品种。设置账户级强平线(亏到总资金50%立即全部清仓)。",ImageType.NONE, listOf("黑天鹅","肥尾","杠铃策略","极端风险"), listOf("risk_001","risk_009","psych_008")),
        KnowledgeItem("risk_013","资金曲线管理",Category.RISK,Level.INTERMEDIATE,
            "管理好资金曲线比管理每笔交易更重要——曲线就是你的成绩单。",
            "健康资金曲线特征：阶梯式上升(大赚小亏)、回撤小(<20%)、夏普>1。危险信号：1.连续亏损后突然全仓押注(报复交易) 2.回撤创新高 3.盈亏曲线和手续费曲线背离(手续费占比上升=过度交易)。监控：每周绘制资金曲线,记录每笔交易标记盈亏。分段管理：初始资金(保守,低仓位)→盈利积累(正常仓位)→超额利润(可适当激进)。回撤>20%暂停并复盘：是策略失效还是执行失误。季度提盈：盈利超过一定额度提取部分利润(落袋防止回吐)。专业交易员都把资金曲线当K线图分析。",ImageType.NONE, listOf("资金曲线","管理","提盈","监控"), listOf("risk_001","risk_002","risk_009")),
        // ========== 交易心理扩展 ==========
        KnowledgeItem("psych_006","交易前检查清单",Category.PSYCHOLOGY,Level.BEGINNER,
            "每天开机交易前花5分钟过一遍清单——避免80%的冲动交易。",
            "盘前检查(9:00前)：1.隔夜外盘走势(美股/原油/伦敦金属) 2.重大新闻(财经日历) 3.持仓品种关键价(支撑/阻力/止损) 4.今日关注品种(最多3个) 5.资金和仓位(可用资金/风险度/持仓)。盘中检查(每笔开仓前)：1.方向符合大周期吗？2.入场信号明确吗？3.止损设好了吗？4.盈亏比≥2:1吗？5.这次交易不是在报复或冲动吗？收市检查(15:00后)：1.所有平仓了吗(当日单)？2.填写交易日志了吗？3.修改的止损单生效了吗？打印贴显示器旁。",ImageType.NONE, listOf("检查清单","盘前","纪律","习惯"), listOf("psych_001","psych_005","risk_007")),
        KnowledgeItem("psych_007","连续亏损的应对",Category.PSYCHOLOGY,Level.ADVANCED,
            "连亏5笔你还能冷静按计划交易吗？这是区分专业和业余的分水岭。",
            "连亏是常态：即使胜率50%的策略,连亏5笔的概率也有3%(每100段就发生3次)。心理阶段：1-2笔无所谓 3-4笔开始焦虑 5-6笔怀疑策略 7+笔想翻本(危险！)。应对：1.连亏3笔立即停手当天不交易(打断负反馈循环) 2.复盘每笔亏损是策略内亏损(正常)还是执行失误 3.连亏5笔后仓位降到正常一半 4.回测该策略历史上最长连亏几次(低于则继续,超过则暂停) 5.运动/深呼吸(生理调节情绪)。核心信念：亏损是交易的一部分,连亏不等于策略失效。",ImageType.NONE, listOf("连续亏损","回撤","应对","心理"), listOf("psych_001","psych_003","risk_009")),
        KnowledgeItem("psych_008","过度自信与回撤",Category.PSYCHOLOGY,Level.INTERMEDIATE,
            "连续盈利后最容易爆仓——赚钱是最危险的时刻。",
            "过度自信信号：1.觉得自己看懂了市场(市场不可完全预测) 2.放大仓位(盈利后觉得之前的仓位太小) 3.降低止损(觉得不会碰到) 4.交易频率增加(越做越多) 5.开始指导别人(好为人师)。最大亏损往往发生在最大盈利之后(自信→大仓位→不设止损→一把亏光)。规律：市场专治各种不服。应对：1.盈利后马上提取部分利润(落袋) 2.大赚后强制降低仓位一周 3.永远不因为几笔盈利就修改仓位规则 4.记录过度自信时刻事后反思。保持谦卑：承认自己对市场一无所知。",ImageType.NONE, listOf("过度自信","回撤","连续盈利","谦卑"), listOf("psych_001","psych_004","risk_009")),
        KnowledgeItem("psych_009","建立你的交易系统",Category.PSYCHOLOGY,Level.ADVANCED,
            "没有交易系统的交易者是赌徒——从零建立你自己的系统。",
            "交易系统六大要素：1.市场选择(做什么品种,不做什么) 2.入场规则(何时买/卖,条件明确可量化) 3.仓位管理(每次下多少) 4.止损规则(哪里认错) 5.止盈/出场规则(何时落袋) 6.策略失效条件(什么情况下停用)。案例系统：品种(甲醇/螺纹/豆粕)+入场(日线MACD金叉+价格在20线上+成交量>5日均量)+仓位(总资金2%风险,计算手数)+止损(入场前低-1跳)+止盈(盈亏比3:1或死叉平仓)+失效(回撤>20%或连续亏损>8次)。系统必须写下来,每笔对照执行。定期回测和优化(每季度一次,不过度优化)。",ImageType.NONE, listOf("交易系统","规则","量化","纪律"), listOf("psych_001","psych_005","strategy_007")),
        // ========== 宏观与基本面扩展 ==========
        KnowledgeItem("macro_004","非农与就业数据",Category.BASIC,Level.INTERMEDIATE,
            "每月第一个周五全球交易员都在盯——非农数据为什么这么重要。",
            "非农就业(美国)：每月第一个周五20:30公布(冬令21:30)。>预期=经济强=利好美元/利空黄金=美股可能先跌后涨(加息预期)。<预期=经济弱=利空美元/利好黄金=可能降息。失业率：<4%接近充分就业,上升预示衰退。平均时薪：涨=通胀压力=加息。ADP(周三公布,小非农)：私人就业,常与非农同向但不完全一致。交易策略：数据公布前轻仓,公布后顺势追(第一波)或等5分钟回调后做第二波(更稳)。黄金和非农高度负相关。每月初请失业金人数(周四)也是高频指标。",ImageType.DIAGRAM, listOf("非农","就业","ADP","失业率"), listOf("macro_001","macro_002","strategy_006")),
        KnowledgeItem("macro_005","美林时钟与资产配置",Category.BASIC,Level.ADVANCED,
            "经济周期像四季——不同季节种不同庄稼。",
            "复苏期(GDP↑+CPI↓)：最佳配置=股票(成长股/科技)。过热期(GDP↑+CPI↑)：大宗商品>股票(周期股),债券最差。滞涨期(GDP↓+CPI↑)：现金为王,商品抗通胀(黄金/原油)。衰退期(GDP↓+CPI↓)：债券最好(降息周期),股票差。当前判断：看GDP增速+CPI趋势+央行政策方向。实际应用：不要机械套用,关注政策(货币/财政)可能改变节奏。多资产配置：股/债/商品/现金按阶段分配比例(不是全押一个)。定投可以穿越周期(长期坚持)。",ImageType.DIAGRAM, listOf("美林时钟","经济周期","资产配置","复苏","衰退"), listOf("macro_001","macro_002","basic_010")),
        KnowledgeItem("macro_006","ISM与消费者信心",Category.BASIC,Level.INTERMEDIATE,
            "美国ISM制造业指数——最灵敏的先行指标。",
            "ISM制造业PMI：月度扩散指数,>50扩张<50收缩。连续高于50=经济健康。新订单分项(最领先)、就业分项(与非农印证)、物价支付(通胀预期)。ISM服务业PMI：服务业占美国GDP 70%,更重要。消费者信心(密歇根大学/咨商会)：消费者对经济前景的看法,影响消费→影响公司盈利→影响股市。中国先行指标：社融(每月10日左右)、PMI(月底/月初)、发电量/货运量(高频)。领先指标结构：PMI(领先2-3月)→企业盈利(同步)→就业(滞后)。",ImageType.DIAGRAM, listOf("ISM","PMI","消费者信心","领先指标"), listOf("macro_001","macro_002","macro_004")),
        KnowledgeItem("macro_007","原油基本面分析",Category.BASIC,Level.ADVANCED,
            "原油是大宗之王——供给需求库存三大支柱。",
            "供给端：OPEC+减产/增产(最重要)、美国页岩油产量(EIA每周三公布)、地缘政治(俄罗斯/中东/委内瑞拉)。需求端：全球经济增速(GDP)、航空/交通需求(疫情后恢复)、炼厂开工率(季节性检修)。库存：EIA原油库存(每周三22:30,>预期利空<预期利好)、API库存(周二凌晨,先行指标)、库欣地区库存(WTI交割地)。价差：WTI-Brent价差(反映美欧基本面差异)、月差(近月-远月正价差=现货紧)。裂解价差(汽油-原油)=炼厂利润。原油是政治商品加经济商品,分析难度最高。",ImageType.DIAGRAM, listOf("原油","OPEC","EIA库存","页岩油"), listOf("futures_005","futures_007","macro_003")),
        KnowledgeItem("macro_008","黄金投资框架",Category.BASIC,Level.INTERMEDIATE,
            "黄金不是大宗商品而是货币的替代品——分析逻辑完全不同。",
            "黄金(GC/沪金AU)：全球最古老的避险资产。核心逻辑：黄金与美元实际利率负相关(实际利率=名义利率-通胀预期)。名义利率降(降息)+通胀预期升=黄金大涨(最优环境)。名义利率升(加息)+通胀预期降=黄金承压(最差环境)。供需：央行购金(中俄土印等增储,长期利多)、珠宝需求(印度中国节日)、ETF持仓(SPDR Gold Trust)。避险：战争/危机→金价短期涨但持续性取决于利率。数字黄金：BTC分走部分避险需求(黄金与BTC走势逐渐分化)。操作：黄金期货/黄金ETF(518880)/纸黄金/实物金条。",ImageType.DIAGRAM, listOf("黄金","实际利率","避险","央行购金"), listOf("macro_003","futures_005","futures_008")),
        // ========== 其他补充 ==========
        KnowledgeItem("basic_021","盘口语言解密",Category.BASIC,Level.ADVANCED,
            "买卖五档挂单藏着的暗语——看懂盘口不再被主力戏耍。",
            "买一/卖一挂大单：卖一挂万手大单但不成交→压盘诱空,可能在买二买三偷偷吃货。买一大单不断撤单重挂→托单诱多(制造支撑假象)。吃单速度：卖一被连续吃掉但价格不涨→主力在出货(买一不断挂新单托价)。尾盘大单：收盘前1秒拉高1-2%=做收盘价(次日高开出货)。开盘大单：集合竞价砸低开盘诱空。盘中异动大单：突然万手单瞬间吃掉多个价位=主力进场/离场信号。盘口语言是概率游戏不是确定信号,必须结合K线和量。Level-2数据(10档行情)才能看到更深挂单。",ImageType.NONE, listOf("盘口","挂单","压盘","托单","大单"), listOf("basic_001","basic_020","strategy_005")),
        KnowledgeItem("basic_022","筹码分布与成本分析",Category.BASIC,Level.ADVANCED,
            "筹码分布告诉你套牢盘和获利盘在哪——预测阻力支撑的新维度。",
            "筹码分布(移动成本分布)：横轴=价格,纵轴=该价格的持仓量。密集区=大量投资者成本在此→支撑/阻力极强。获利比例：>90%=都在赚钱→获利回吐压力大,<10%=深套→反弹到密集区下沿会遇抛压。筹码双峰：上方套牢峰+下方获利峰,价格在两峰间运行,突破哪边往哪走。单峰密集：筹码高度集中在窄区间→即将选择方向(横盘突破)。低位锁仓：低位筹码不卖(主力持仓)→后市可期。高位筹码分散=主力出货完毕。注意：筹码分布是估算值(基于换手率模拟),不完全精确。",ImageType.CHART, listOf("筹码分布","成本","套牢盘","获利盘"), listOf("basic_001","basic_010","strategy_019")),
        KnowledgeItem("basic_023","数字货币入门",Category.BASIC,Level.BEGINNER,
            "比特币/以太坊——另类资产还是数字黄金？",
            "BTC(比特币)：总量2100万,去中心化,数字黄金叙事。ETH(以太坊)：智能合约平台,DeFi和NFT的底层。交易方式：币安/OKX等中心化交易所(7×24交易,无涨跌停,T+0)。USDT/USDC：与美元1:1锚定的稳定币。与股市关系：BTC与纳指相关性逐年上升(从<0.2到0.5+),不再是独立资产。ETF：美国已通过BTC现货ETF(IBIT/FBTC等),香港也通过。风险：波动极大(日波动5-10%常见)、监管不确定、交易所跑路风险。期货：CME有BTC/ETH期货合约。建议：配置<总资产5%,当做高风险另类资产。",ImageType.NONE, listOf("比特币","以太坊","BTC","数字货币"), listOf("basic_001","macro_008","futures_005")),
        KnowledgeItem("basic_024","REITs房地产信托",Category.BASIC,Level.BEGINNER,
            "买不起房也能当房东——REITs让你用几千块投资商业地产。",
            "REITs(房地产投资信托)：像股票一样交易,持有商业地产(写字楼/商场/物流园/公寓/数据中心)收租。优势：高分红(法律要求90%以上利润分红,股息率通常4-8%)、流动性好(交易所买卖)、分散投资。A股REITs：产业园(张江/蛇口)、高速公路、仓储物流(普洛斯/京东)、保障房。港股REITs：领展(0823,亚洲最大)。美股REITs：数据机房(EQIX)、铁塔(AMT)、仓储(PLD)。风险：利率升→不利(融资成本高+折现率高)、经济衰退→租金降。REITs与债券走势趋同(利率敏感)。适合：追求稳定现金流+中低风险的长期投资者。",ImageType.NONE, listOf("REITs","房地产","信托","分红"), listOf("basic_001","basic_011","macro_005")),
        KnowledgeItem("basic_025","全球主要交易所",Category.BASIC,Level.BEGINNER,
            "纽约、伦敦、东京、香港、上海——一张表看懂全球交易时间。",
            "纽约(NYSE/NASDAQ)：全球最大,美东9:30-16:00/北京21:30-4:00(夏)22:30-5:00(冬)。伦敦(LSE)：8:00-16:30/北京15:00-23:30(夏)16:00-0:30(冬)。东京(JPX)：9:00-15:00(午休11:30-12:30)/北京同。香港(HKEX)：9:30-16:00/与北京同。上海/深圳：9:30-15:00。期货交易所：CME(芝加哥/全球最大衍生品)、LME(伦敦金属)、ICE(洲际/原油/糖/棉花)、SGX(新加坡/A50期指)、EUREX(欧洲/德指)。24小时接力：东京→上海/香港→伦敦→纽约→芝加哥(期货)几乎全天候交易。",ImageType.NONE, listOf("交易所","纽交所","伦交所","港交所","CME"), listOf("basic_001","basic_018","basic_019")),
        KnowledgeItem("term_007","技术分析术语A-Z",Category.TERMINOLOGY,Level.BEGINNER,
            "金叉/死叉/背离/乖离/顶底——技术分析常用术语速查。",
            "金叉：快线上穿慢线(如MACD金叉/均线金叉)=买入信号。死叉：快线下穿慢线=卖出信号。背离：价格和指标方向不一致,顶背离(价涨指标跌)=反转。乖离：价格偏离均线的幅度(正乖离过大超买)。超买/超卖：指标达到极端值(RSI>70超买,<30超卖)。底/顶：底部=止跌企稳区域,顶部=见顶回落区域。背驰：同背离(禅论用语)。钝化：指标在高位/低位横盘不再变化(强势单边中常见)。共振：多个指标/周期同时发出信号。回踩/回抽：突破后回到突破点测试支撑。诱多/诱空：假突破后反向杀。",ImageType.NONE, listOf("金叉","死叉","背离","术语"), listOf("term_001","term_002","term_005")),
        KnowledgeItem("term_008","期货交易术语补遗",Category.TERMINOLOGY,Level.INTERMEDIATE,
            "期货市场特有的术语——不懂这些没法看研报。",
            "基差=现货-期货(正基差=现货强,负基差=现货弱)。Contango：远月高于近月=正向市场(正常,体现持有成本)。Backwardation：近月高于远月=反向市场(现货紧缺)。展期/移仓：将持仓从近月合约换到远月(近月到期前)。跨期价差：不同月份合约价差。仓单：交易所注册的标准仓单(可交割凭证)。虚实盘比=持仓量/仓单量(>10警惕逼仓)。仓单预报：现货商申请注册仓单的数量(大增=准备交货)。升贴水：期货对现货的溢价(升水)/折价(贴水),或某地对基准地的价差。沉淀资金：某品种的总保证金≈持仓量×合约乘数×价格×保证金比例。",ImageType.NONE, listOf("基差","Contango","展期","虚实比"), listOf("term_003","term_004","futures_010")),
        KnowledgeItem("term_009","期权交易术语速查",Category.TERMINOLOGY,Level.INTERMEDIATE,
            "Call/Put/ITM/OTM/IV——期权世界的常用黑话。",
            "Call：看涨期权(买方有权以执行价买入)。Put：看跌期权(买方有权以执行价卖出)。执行价/行权价：合约规定的买卖价格。权利金：期权的价格(买方支付给卖方)。内在价值=标的价格-执行价(仅ITM时有)。时间价值=权利金-内在价值(随时间衰减归零)。ITM(实值)：标的价格>执行价(Call)或<执行价(Put),有内在价值。ATM(平值)：标的价格≈执行价。OTM(虚值)：无内在价值,只有时间价值。IV(隐含波动率)：市场对未来波动的预期,IV升=期权贵。HV(历史波动率)：过去实际波动率。偏度Skew：OTM Put的IV通常高于OTM Call(崩盘恐惧溢价)。",ImageType.NONE, listOf("Call","Put","ITM","IV","权利金"), listOf("term_003","term_004","options_001")),
        KnowledgeItem("basic_026","财经资讯与数据源",Category.BASIC,Level.BEGINNER,
            "去哪看财经新闻和专业数据——信息源决定你的认知层级。",
            "免费网站：东方财富(eastmoney,最全A股/F10)、同花顺(10jqka,社区活跃)、金十数据(宏观/期货/7×24快讯)、华尔街见闻(全球宏观)、雪球(高质量讨论)。期货专用：文华财经随身行APP、生意社(100ppi.com,现货价格/大宗商品)、钢联(mysteel,黑色系)、卓创资讯。外文：Reuters/Bloomberg/Yahoo Finance/Investing.com。数据平台：Tushare(免费A股数据/Python)、聚宽/米筐(回测)、Wind(付费/专业机构)。研报：慧博/萝卜投研(免费研报聚合)。避坑：远离微信荐股群、抖音炒股直播、杀猪盘短信。",ImageType.NONE, listOf("财经资讯","数据源","研报","信息"), listOf("basic_001","strategy_006","strategy_015")),
        // ========== 投资组合理论 ==========
        KnowledgeItem("basic_027","现代投资组合理论",Category.BASIC,Level.ADVANCED,
            "马科维茨1952年的一篇论文——如何用数学分散风险。",
            "MPT(现代投资组合理论)：通过组合低相关性资产,在不降低收益的前提下减少风险。有效前沿：所有最优组合构成的一条曲线,曲线上任意点=给定风险下收益最高。核心公式：组合方差=∑(权重i×权重j×协方差ij)。关键是协方差而非单项波动率。加入无风险资产=资本市场线(CML),CML与有效前沿的切点=市场组合(最优风险组合)。分离定理：投资决策=先选最优风险组合,再根据风险承受度分配无风险资产与风险组合比例。A股应用：ETF组合(沪深300+国债ETF+黄金ETF)可构建有效前沿。",ImageType.FORMULA, listOf("MPT","有效前沿","分散","马科维茨"), listOf("basic_001","basic_011","risk_010")),
        KnowledgeItem("basic_028","CAPM与多因子模型",Category.BASIC,Level.ADVANCED,
            "一只股票该值多少钱——CAPM到Fama-French的定价演进。",
            "CAPM(资本资产定价模型)：预期收益=无风险利率+β×(市场风险溢价)。β=股票相对大盘的波动倍数(β>1弹性大,β<1防御型)。局限：CAPM只考虑市场风险,遗漏了市值/价值等因素。Fama-French三因子：市场因子+规模因子(SMB,小盘溢价)+价值因子(HML,低估溢价)。五因子：再加盈利因子(RMW)+投资因子(CMA)。A股因子有效性：小市值(长期溢价但波动大)、低估值(价值因子显著)、动量(短期有效)、低波(红利股)。因子择时极难,多因子均衡配置更稳。",ImageType.FORMULA, listOf("CAPM","β","Fama-French","因子"), listOf("basic_001","basic_027","strategy_013")),
        // ========== 债券专题 ==========
        KnowledgeItem("basic_029","债券基础入门",Category.BASIC,Level.BEGINNER,
            "债券不是只有老头老太太才买——固定收益市场的底层逻辑。",
            "债券=借条。面值(通常100元)、票息(每年付多少利息)、到期日(还本日)。收益率≠票息：你花95元买面值100的债券,到期收益率更高。价格与利率反向：利率上升→债券跌,利率下降→债券涨(新发债券票息更高旧债就不值钱了)。国债(国家信用,最安全)、地方债/城投债(隐含政府信用)、信用债(企业债/公司债,有违约风险)、可转债(股债双属性已讲)。债券ETF：国债ETF(511010/511260)、城投债ETF(511220)。投资债基/货基间接参与。债券期货：2/5/10/30年国债期货。",ImageType.DIAGRAM, listOf("债券","国债","票息","收益率"), listOf("basic_001","basic_011","futures_023")),
        KnowledgeItem("basic_030","收益率曲线与久期",Category.BASIC,Level.ADVANCED,
            "收益率曲线的形状是经济前景的预言家。",
            "收益率曲线(Yield Curve)=不同期限(1月/1年/2/5/10/30年)国债收益率的连线。正常形态(陡峭)：长期>短期,经济扩张预期。平坦形态：长短端接近,经济放缓信号(央行加息短端上升)。倒挂形态：短期>长期(如2年>10年),历史上最准的衰退指标(发生在衰退前12-18个月)。久期(Duration)：衡量债券对利率的敏感度,久期=5表示利率变动1%债券价格变动≈5%。修正久期、麦考利久期。组合久期管理：看多利率(预期降息)=拉长久期(买长债)。应用：用国债期货对冲组合久期风险。",ImageType.CHART, listOf("收益率曲线","久期","倒挂","利率风险"), listOf("basic_029","macro_002","futures_023")),
        KnowledgeItem("basic_031","信用债与信用评级",Category.BASIC,Level.INTERMEDIATE,
            "不是所有债都安全——信用下沉的风险与收益。",
            "信用评级：AAA(最高)/AA+/AA/AA-/A+/A/BBB(投资级分界线)/BB+(投机级=高收益债=垃圾债)。评级下调=债券跌。信用利差=信用债收益率-同期限国债收益率,经济差时利差走阔(风险偏好降),经济好时利差收窄。城投债：地方政府融资平台发债,名义非政府债但市场视为有政府隐性担保(15万亿+存量)。房地产债：2021年后暴雷不断(恒大/碧桂园等)→高收益但也可能血本无归。可转债(已详述)。投资方式：信用债ETF/债基(分散持有,不赌单券)。散户直接投资门槛高(合格投资者500万),建议走公募基金。",ImageType.DIAGRAM, listOf("信用债","评级","信用利差","城投债"), listOf("basic_029","basic_030","risk_010")),
        // ========== A股制度专题 ==========
        KnowledgeItem("basic_032","注册制改革",Category.BASIC,Level.INTERMEDIATE,
            "从审批制到核准制再到注册制——A股发行制度的30年进化。",
            "审批制(1990-2001)：政府批指标,额度管理=计划色彩浓。核准制(2001-2023)：证监会实质审核(盈利要求/排队/漫长)。注册制(2019科创板→2020创业板→2023全面注册制)：交易所审核+证监会注册,核心是信息披露(不判好坏,只判真假)。变化：上市门槛降低(亏损也可上市)、退市力度加大、打新稳赚神话破灭(首日破发成常态)、壳价值暴跌。影响：IPO数量激增(每年300-400家),市场从供不应求变供过于求→考验选股能力。散户应对：远离ST和亏损次新股,坚守优质龙头。",ImageType.NONE, listOf("注册制","IPO","科创板","上市"), listOf("basic_001","basic_009","basic_015")),
        KnowledgeItem("basic_033","退市与ST制度",Category.BASIC,Level.INTERMEDIATE,
            "注册制下退市常态化——不小心踩雷ST可能血本无归。",
            "ST(特别处理)：连续两年亏损/净资产为负/审计否定意见等→戴帽ST,涨跌幅5%。*ST(退市风险警示)：更严重,可能退市。退市标准：1元退市(连续20日<1元,最常见)、3亿市值退市、财务类(扣非净利润亏损+营收<1亿)、规范类(财报造假/无法表示意见)、重大违法类。退市流程：风险警示→退市整理期(15个交易日,涨跌幅20%)→摘牌→转三板(流动性极差)。散户避坑：不碰股价<2元+没有业绩的票、财报非标意见直接拉黑、不赌ST摘帽(概率游戏)。注册制下退市加速(2022退市46家,2023退市44家)。",ImageType.NONE, listOf("ST","退市","*ST","戴帽"), listOf("basic_001","basic_032","risk_012")),
        KnowledgeItem("basic_034","定增、配股与借壳",Category.BASIC,Level.INTERMEDIATE,
            "上市公司融资和重组的三种常见方式——对股价影响各不同。",
            "定增(非公开发行)：向特定机构折价发行新股融资(通常折价10-20%,有6-18个月锁定期)。对散户：短期利空(稀释EPS/低价拿货),但如果投向好项目长期利多。定增新规：不得超过总股本30%、间隔18个月。配股：向所有老股东按比例配售(如10配3),配股价通常远低于市价。不参与配股=股价除权后直接亏损→必须参与或提前卖出。借壳上市：未上市公司买壳(收购上市公司控股权再注入资产)。注册制后壳价值暴跌(借壳需求大降)。要约收购/协议收购/二级市场举牌(持股>5%需公告,>30%触发要约)。",ImageType.DIAGRAM, listOf("定增","配股","借壳","收购"), listOf("basic_001","basic_009","basic_032")),
        // ========== 选股方法 ==========
        KnowledgeItem("strategy_022","财务指标选股法",Category.STRATEGY,Level.INTERMEDIATE,
            "用数字筛股票——一套可落地的财务筛选框架。",
            "盈利能力：ROE>15%(连续3-5年)、毛利率>30%(越高护城河越深)、净利率>10%、自由现金流>净利润。成长性：营收增速>15%、净利润增速>20%(且增速不下降)。财务健康：负债率<50%(除金融地产)、流动比率>1.5、经营现金流/净利润>0.8。估值：PE<行业均值且<30倍(成长股可放宽)、PEG<1、PB<3。分红：股息率>2%且持续5年以上。过滤：上市>3年(次新股先观察)、大股东质押率<50%、商誉/净资产<30%。实操：用同花顺i问财/东方财富选股器设置条件筛选,再进行人工判断。",ImageType.FORMULA, listOf("ROE","PEG","毛利率","选股"), listOf("basic_009","basic_001","strategy_001")),
        KnowledgeItem("strategy_023","ROE-PB估值框架",Category.STRATEGY,Level.ADVANCED,
            "ROE决定PB——同一个公式理解巴菲特的价值投资。",
            "核心公式：合理PB=ROE/要求回报率。ROE=20%+要求回报10%→合理PB=2。原理：ROE是公司为股东创造回报的能力,PB是你为这个能力付的价。高ROE+低PB=低估。应用：ROE>20%+PB<3=优质低估(如茅台30%ROE对应8-10PB也不贵)。ROE<5%+PB<0.5=价值陷阱(看着便宜但垃圾)。ROE的趋势比绝对值重要(ROE上升中+PB合理=最佳买点)。杜邦分析法拆ROE：净利率×周转率×杠杆倍数,找到ROE的来源(高利润率vs高杠杆→前者更优)。ROIC(投入资本回报率)排除杠杆效应,比ROE更纯粹。",ImageType.FORMULA, listOf("ROE","PB","估值","杜邦分析"), listOf("basic_009","basic_015","strategy_022")),
        KnowledgeItem("strategy_024","护城河与竞争优势",Category.STRATEGY,Level.ADVANCED,
            "巴菲特说的护城河到底是什么——识别真正值得长期持有的公司。",
            "护城河类型：1.品牌(茅台/可口可乐,消费者溢价支付) 2.转换成本(微软Office/微信,换的成本太高) 3.网络效应(淘宝/美团,用的人越多价值越高) 4.规模成本优势(宁德时代/海螺水泥,规模越大单位成本越低) 5.专利/牌照(医药专利/金融牌照,法定壁垒)。识别：毛利率持续>40%且稳定、持续涨价而销量不减、竞争对手很难复制。宽护城河+ROE>15%+合理估值=长期持有(以年为单位)。窄护城河=周期性/贸易类(机会主义交易)。无护城河=最危险(纯靠风口和炒作)。护城河也会被颠覆(柯达/诺基亚)→持续关注竞争格局变化。",ImageType.NONE, listOf("护城河","竞争优势","品牌","壁垒"), listOf("strategy_022","strategy_023","basic_010")),
        // ========== 订单执行 ==========
        KnowledgeItem("futures_029","算法交易与执行",Category.FUTURES,Level.ADVANCED,
            "大资金如何悄悄入场——TWAP/VWAP/冰山单全解析。",
            "TWAP(时间加权均价)：把一个大单拆成N个小单,按时间均匀分布(如每5秒下1手)。优势：最小化市场冲击。VWAP(成交量加权均价)：按历史成交量分布拆单(成交量大的时段多下单,如开盘和尾盘)。TWAP简单但易被识别,VWAP更隐蔽但需预估成交量分布。冰山单(Iceberg)：挂单只显示总手数的一部分(如10%),被吃掉后自动刷新,隐藏真实意图。狙击(Sniper)：被动等待对手单出现再瞬间成交(需高速行情)。A股实现：量化交易接口(Python连接券商API)、通达信/同花顺条件单、QMT/PTrade量化平台。注：高频和算法交易需技术和速度优势,散户不建议。",ImageType.DIAGRAM, listOf("TWAP","VWAP","冰山单","算法交易"), listOf("strategy_017","futures_026","risk_008")),
        KnowledgeItem("futures_030","下单策略与执行技巧",Category.FUTURES,Level.INTERMEDIATE,
            "限价单还是市价单？——下单策略直接影响交易成本。",
            "限价单(Limit Order)：指定买入价(≤市场价)或卖出价(≥市场价)。优点=控制成交价,缺点=可能不成交(踏空)。市价单(Market Order)：即时按最优价成交。优点=保证成交,缺点=滑点(实际价≠预期价)。止损单(Stop Order)：触发价格后转为市价单(如螺纹止损3500,跌破3500即市价平仓)。条件单：满足条件自动下单(如IF突破4000即买入)。OCO(二选一)：同时挂止损+止盈,触发一个取消另一个。分批入场：不确定方向时先建1/3仓位(试仓),确认后再加。流动性：流动性差的品种用限价单(滑点大),主力合约可用市价单(盘口厚)。",ImageType.DIAGRAM, listOf("限价单","市价单","止损单","条件单"), listOf("strategy_017","futures_001","risk_007")),
        // ========== AI与量化 ==========
        KnowledgeItem("strategy_025","AI量化投资入门",Category.STRATEGY,Level.ADVANCED,
            "机器学习正改变量化交易——不用成为博士也能理解。",
            "监督学习：用历史数据(X=指标/价格/量)预测未来涨跌(Y)。算法：线性回归/决策树/随机森林/XGBoost/LightGBM(效果最好)/LSTM神经网络。特征工程：原始数据(开盘/收盘/量)→技术指标(RSI/MACD)→衍生特征(RSI变化率/量比/波动率因子)。过拟合是最大陷阱：回测完美实盘崩。防御：交叉验证/样本外测试/简化模型。强化学习：AI在模拟环境中不断试错学习最优策略(Deep Q-Network等)但A股/期货真实应用中极难稳定。建议：初学者从XGBoost+LSTM混合模型+简单因子开始,Baostock/Tushare获取数据,聚宽做回测。不要神化AI。",ImageType.FORMULA, listOf("机器学习","XGBoost","LSTM","过拟合"), listOf("strategy_007","strategy_013","futures_026")),
        KnowledgeItem("strategy_026","舆情分析与情绪指标",Category.STRATEGY,Level.ADVANCED,
            "恐惧与贪婪如何量化——情绪指标是反向交易的法宝。",
            "VIX(恐慌指数)：CBOE波动率指数,市场恐慌时飙升(>30恐慌,<15平静)。VIX与股市负相关。A股隐波：50ETF期权隐含波动率(类似VIX)。Put/Call比率：看跌期权量/看涨期权量,过高=过度恐慌(可能见底)。散户情绪：百度指数(搜索热度)、东方财富股吧情绪(用NLP抓取)、融资余额变化(散户加杠杆=亢奋)。北向资金：外资买入/卖出趋势。AAII情绪调查(美国散户看多比例)、CNN恐惧贪婪指数(7因子复合)。恐慌时往往是最佳买入时机(别人恐惧我贪婪)。不依赖单一情绪指标,多信号共振更准。",ImageType.DIAGRAM, listOf("VIX","恐慌","情绪","NLP","舆情"), listOf("strategy_021","macro_006","psych_004")),
        // ========== 全球宏观补充 ==========
        KnowledgeItem("macro_009","新兴市场投资",Category.BASIC,Level.INTERMEDIATE,
            "除了A股美股——新兴市场的机会与风险。",
            "BRICS：巴西(资源国/铁矿大豆)、俄罗斯(能源/被制裁后边缘化)、印度(人口红利/增长最快/孟买SENSEX)、中国、南非(黄金/铂金)。东南亚：越南(VN30/人口红利/制造业转移)、印尼(资源/镍矿)、泰国(SET)。新兴市场共性：高增长+高波动+汇率风险+政策风险。投资渠道：新兴市场ETF(如EEM/VWO美股上市)、A股可通过港股通间接参与。美元周期：美元弱→资金流入新兴市场利好,美元强→资金流出新兴市场利空(2022年验证)。新兴市场债：高收益+高违约风险。配置建议：总资产5-15%,看好印度越南,谨慎拉美和土耳其。",ImageType.DIAGRAM, listOf("新兴市场","印度","越南","BRICS"), listOf("basic_019","basic_025","macro_003")),
        KnowledgeItem("macro_010","地缘政治与市场",Category.BASIC,Level.ADVANCED,
            "战争、制裁、贸易战——地缘政治如何影响你的持仓。",
            "能源价格：中东/俄罗斯冲突→原油飙升(利好能源期货/利空航空化工)。供应链中断：芯片战(中美)→国产替代概念涨(中芯国际/北方华创)/依赖进口的跌。制裁：被制裁国货币暴跌+外债违约(2018俄罗斯/2022俄罗斯)。避险资产：冲突爆发→黄金涨/美元涨/美债涨/VIX飙升→股票短期跌(但往往V形反弹)。贸易战(2018中美)：大豆(中国转向巴西采购→美豆跌内盘豆粕涨)、芯片(国产替代)、稀土(中国反制筹码)。核心：战争恐慌=买点(历史上除二战外,战争对美股长期几乎无影响)。关注：台海/南海/朝鲜半岛,这些是影响A股/港股最直接的地缘因子。",ImageType.DIAGRAM, listOf("地缘政治","战争","制裁","避险"), listOf("macro_003","macro_007","macro_008")),
        // ========== 期权进阶 ==========
        KnowledgeItem("options_005","波动率曲面与波动率微笑",Category.BASIC,Level.ADVANCED,
            "为什么不同执行价的期权IV不一样——波动率微笑是市场的恐惧定价。",
            "波动率微笑(Volatility Smile)：横轴执行价,纵轴隐含波动率(IV),图形呈微笑状。成因：OTM Put的IV最高(崩盘恐惧溢价,1987后永久存在)、ATM的IV最低、深度OTM Call也有溢价(暴涨预期)。波动率偏斜(Skew)：Put端IV高于Call端(正常偏斜,大多数品种)。波动率期限结构：横轴到期日,纵轴IV。通常远月IV>近月(Contango),恐慌时反转(Backwardation,近月飙升)。波动率曲面组合两个维度(执行价+到期日)。实战意义：不同执行价的期权被不同定价→卖出高IV端+买入低IV端=波动率套利。IV百分位>80%=IV偏高可考虑卖方策略。",ImageType.CHART, listOf("波动率微笑","偏斜","曲面","IV"), listOf("options_001","options_002","options_003")),
        KnowledgeItem("options_006","日历价差与对角价差",Category.BASIC,Level.ADVANCED,
            "赚取时间衰减的差异——专业期权交易者的入门策略。",
            "日历价差(Calendar Spread)：卖近月+买远月(同方向同执行价)。逻辑：近月时间衰减快于远月(Theta不对称)。赚取的是时间价值差。理想条件：标的价格≈执行价(ATM日历)、IV处于低位(买入便宜远月期权)。风险：IV大幅变动(尤其近月到期日的Gamma风险)。对角价差：卖近月+买远月但执行价不同(如卖近月OTM Call+买远月ATM Call)。兼具方向和时间维度。反向日历：买近月+卖远月(看涨IV或方向)。适用：盘整行情最佳,突破或IV骤升=亏损。需动态管理(近月到期前必须平仓或展期)。",ImageType.DIAGRAM, listOf("日历价差","对角价差","Theta","时间衰减"), listOf("options_002","options_004","options_005")),
        KnowledgeItem("options_007","比率价差与合成策略",Category.BASIC,Level.ADVANCED,
            "用不对称的腿构建零成本或低成本的策略。",
            "比率价差(Ratio Spread)：卖多+买少(如卖2手Call+买1手Call,同一到期日不同执行价)。零成本/低成本。盈利区=窄幅波动(在卖的执行价附近最好)。风险：价格大涨突破卖的执行价→亏损无限放大(卖的数量>买的数量)。反比率：买多+卖少(如买2手Put+卖1手Put,看大跌)。合成多头(Synthetic Long)：买Call+卖Put(同执行价同到期),盈亏曲线=股票多头,不需买股票。合成空头：买Put+卖Call=股票空头。转换/反转套利：利用合成头寸与标的之间的价差无风险套利(专业做市商玩法)。箱体价差(Box Spread)：用4条腿锁定无风险利息收益。",ImageType.DIAGRAM, listOf("比率价差","合成策略","转换套利","箱体"), listOf("options_001","options_002","options_003")),
        // ========== 行业分析 ==========
        KnowledgeItem("basic_035","消费行业投资框架",Category.BASIC,Level.INTERMEDIATE,
            "民以食为天——消费行业的确定性是最值钱的资产。",
            "必选消费(防御型)：食品饮料/日化/超市,经济再差也得消费。龙头：茅台(白酒)、海天/中炬(调味品)、伊利(乳业)、金龙鱼(粮油)。核心指标：ROE>20%(茅台30%+)、毛利率>60%、渠道覆盖(经销商数量)、品牌力(提价能力)。可选消费(周期型)：汽车/家电/服装/旅游/教育,经济好时爆发力强。龙头：比亚迪/长城(汽车)、美的/格力(家电)、安踏/李宁(运动)。估值：必选消费PE通常25-40倍(高确定性溢价),可选消费PE波动大(15-50倍)。风险：食品安全事件(三聚氰胺/塑化剂,短期暴跌但往往是黄金坑)、消费降级(拼多多化)、行业政策。",ImageType.NONE, listOf("消费","白酒","食品饮料","品牌"), listOf("basic_010","strategy_022","strategy_024")),
        KnowledgeItem("basic_036","医药行业投资逻辑",Category.BASIC,Level.INTERMEDIATE,
            "老龄化+创新——医药行业的黄金赛道也是政策雷区。",
            "细分赛道：1.创新药(恒瑞/百济,研发管线驱动,高风险高回报) 2.医疗器械(迈瑞/微创,国产替代逻辑) 3.CXO(药明/康龙,卖铲子,跟随全球研发支出) 4.中药(片仔癀/同仁堂,品牌+国家政策扶持) 5.医药流通(国药/上药,低毛利高周转) 6.医疗服务(爱尔眼科/通策,连锁扩张)。集采(带量采购)：医保局以量换价,仿制药价格跌80-90%,仿制药企盈利崩塌。创新药不受集采影响(专利保护)。FDA获批=出海逻辑(如百济泽布替尼)。估值：创新药用管线估值(DCF+峰值销售折现),中药看PE+PEG+品牌溢价。风险：集采政策、研发失败、专利悬崖、国际关系(药明生物UVL事件)。",ImageType.NONE, listOf("医药","创新药","CXO","集采"), listOf("basic_010","basic_035","strategy_022")),
        KnowledgeItem("basic_037","科技行业投资要点",Category.BASIC,Level.INTERMEDIATE,
            "从半导体到AI——科技行业判断对趋势就成功了一半。",
            "半导体：国产替代最硬逻辑(中芯国际/北方华创/韦尔股份)。周期性强(2-3年一轮,库存周期)。跟踪指标：费城半导体指数、全球半导体销售额、台积电/三星CAPEX指引。消费电子：苹果概念(立讯/歌尔)、华为回归、AI手机/AI PC换机潮。软件：信创(金山/用友/中望,国产替代),SaaS(估值看PS和ARR增长)。新能源：光伏(隆基/通威,产能过剩价格战)、锂电(宁德/比亚迪,产能过剩+技术迭代)、储能(新增长极)。AI：算力(光模块中际旭创/天孚通信)、应用(找不到对标,还在讲故事)。科技股特征：高PE+高波动,趋势投资>价值投资。风险：技术路线被颠覆、美国制裁(华为/中芯)、产能过剩。",ImageType.NONE, listOf("科技","半导体","AI","新能源"), listOf("basic_010","basic_035","macro_010")),
        KnowledgeItem("basic_038","周期与金融行业",Category.BASIC,Level.INTERMEDIATE,
            "周期股赚波动的钱,金融股赚利差的钱。",
            "周期行业特征：利润跟随大宗商品/经济周期大幅波动,高PE时买入(利润低谷),低PE时卖出(利润高峰)。钢铁(宝钢/华菱,跟踪螺纹/热卷+铁矿石价差)、有色(紫金矿业/洛阳钼业,铜金钼钴,跟踪LME+美元)、化工(万华化学/恒力石化,炼化/MDI,跟踪油价+价差)、煤炭(中国神华/陕西煤业,高股息+动力煤价)。工程机械(三一重工/恒立液压,跟踪开工小时数+基建投资)。金融行业：银行(工行/招行/宁波,息差+资产质量,NIM走势是核心)、券商(中信/东财,市场成交量放大器,牛市翻倍股)、保险(平安/太保,负债端(新业务价值)+资产端(利率/权益))。银行股息率5-7%(红利逻辑),券商弹性大(牛市急先锋),保险兼具防御和弹性。风险：地产风险传导(银行坏账)、利率下行(保险压力)。",ImageType.NONE, listOf("周期","银行","券商","保险"), listOf("basic_010","basic_035","macro_004")),
        // ========== 财务深入 ==========
        KnowledgeItem("basic_039","现金流量表深度解析",Category.BASIC,Level.ADVANCED,
            "利润可以粉饰,现金流不会撒谎——三张表里最重要的一张。",
            "三大现金流：经营活动(卖货收的钱-付供应商/工资,公司造血能力)、投资活动(买设备/投资/收购,花在未来的钱)、筹资活动(借债/发股/分红,外部输血)。自由现金流(FCF)=经营活动现金流-资本支出,是公司真正能分配给股东的钱。判断：经营现金流>净利润=利润含金量高(反之=纸面利润)、经营现金流持续为负=危险(造血能力丧失)、FCF>0且增长=优质公司。现金流表造假比利润表难(银行流水做不了假)。案例：某园林公司利润年年增但经营现金流连年为负→最终暴雷(应收账款全是白条)。投资核心：现金流是照妖镜,利润能骗人现金流骗不了。",ImageType.FORMULA, listOf("现金流量表","FCF","经营现金流","造血"), listOf("basic_008","basic_009","strategy_022")),
        KnowledgeItem("basic_040","商誉与研发资本化陷阱",Category.BASIC,Level.ADVANCED,
            "上市公司财报的两个最大雷区——一炸就归零。",
            "商誉(Goodwill)：收购时支付价格高于净资产的部分。A股商誉池近1.5万亿(2024)。商誉减值：被收购公司业绩不达预期→一次性计提商誉减值(直接减少净利润)。案例：某影视公司收购明星空壳公司后商誉减值数十亿→股价暴跌80%+。防雷：商誉/净资产>30%=高度警惕、收购对象利润断崖式下滑=减值前兆、跨界并购(主业A买B行业)商誉暴雷概率最高。研发资本化：把研发支出变成资产而非费用→美化利润(如某药企研发资本化率>50%但同行<10%→利润虚增)。判断：对比同行资本化比例、费用化越保守的公司越诚信。费用化研发直接减少利润但保守,资本化反之——但对价值无影响(只是会计选择)。",ImageType.NONE, listOf("商誉","减值","研发资本化","财务陷阱"), listOf("basic_008","basic_009","basic_039")),
        KnowledgeItem("basic_041","三表联动分析",Category.BASIC,Level.ADVANCED,
            "利润表+资产负债表+现金流量表——三表勾稽关系是财务分析的核心。",
            "核心勾稽：净利润(利润表)→调整后→经营活动现金流(现金流量表)。资产负债表未分配利润变动=净利润-分红。折旧/摊销：利润表减项→现金流量表加回(非现金支出)。应收账款：利润表确认了收入→但尚未收到现金(现金<利润)→应收账款增加(资产负债表)。存货：产量>销量→存货增加→利润虚增(固定成本分摊到存货而非当期)。投资：固定资产增加→投资现金流支出→折旧影响未来利润表。筹资：借债→筹资现金流流入→资产负债率上升→利息费用影响利润表。综合分析框架：利润增长+现金流同步增长+资产质量改善=真成长。利润增长+现金流恶化+应收账款/存货暴增=财务造假信号。",ImageType.DIAGRAM, listOf("三表联动","勾稽","财务分析","造假识别"), listOf("basic_008","basic_009","basic_039")),
        // ========== 回测方法论 ==========
        KnowledgeItem("strategy_027","量化回测与过拟合防范",Category.STRATEGY,Level.ADVANCED,
            "回测收益1000%实盘血亏——过拟合是量化最大的敌人。",
            "过拟合=策略记住了历史的每一个噪音(pattern),但对未来毫无预测力。表现：回测曲线完美右上45度+实盘一路向下。防范：1.样本外测试(训练集70%+验证集15%+测试集15%,只用训练集开发,测试集绝不碰直到最终评估) 2.交叉验证(滚动时间窗,每段时间分别测试) 3.简化参数(参数越多越容易过拟合,尽量<5个) 4.逻辑优先(策略必须有合理的经济解释,纯数据挖掘=大概率过拟合) 5.稳健性检验(小幅改变参数看结果是否剧烈变化)。事前Sharpe比率(SR)≈0.5-1.0才可持续,SR>2.0=几乎确定过拟合。回测陷阱：未来函数(用当天还不知道的信息)、幸存者偏差(只回测现在活着的股票)。",ImageType.CHART, listOf("过拟合","回测","样本外","Sharpe"), listOf("strategy_007","strategy_013","strategy_025")),
        KnowledgeItem("strategy_028","回测的滑点与手续费建模",Category.STRATEGY,Level.ADVANCED,
            "回测净赚50%实盘还亏钱——你没算交易成本。",
            "手续费：A股印花税0.05%(卖出,2023减半后)+券商佣金万1.5-万3+过户费。期货：交易所手续费(各品种不同,如螺纹万1+开平各收)+期货公司加收。高频策略手续费是最致命因素(可能吃光利润)。滑点(Slippage)：实际成交价与期望价的偏差。原因：市场波动(市价单)、流动性不足(挂单没人吃)、延迟(网络)。估算：股票0.05-0.2%单边、期货1-3跳(根据流动性)。建模：根据策略频率合理加(日频0.05%、分钟级0.1%、Tick级0.15%+)。冲击成本：大资金入场推高价格(买)或压低价格(卖),散户无需考虑。回测教训：任何策略回测毛利率<5%的直接放弃(扣成本就没了)。",ImageType.FORMULA, listOf("滑点","手续费","冲击成本","交易成本"), listOf("strategy_027","strategy_017","futures_029")),
        // ========== 看盘实战 ==========
        KnowledgeItem("basic_042","集合竞价实战指南",Category.BASIC,Level.BEGINNER,
            "9:15-9:25这10分钟——每天最重要的交易窗口。",
            "A股集合竞价时间：9:15-9:20(可挂可撤)、9:20-9:25(可挂不可撤,主力不能骗线了)、9:25-9:30(不可挂不可撤)。撮合原则：最大成交量原则(选出使成交量最大的那个价格作为开盘价)。高开/低开判断：9:25前看虚拟匹配价和成交量分布。主力套路：9:18-9:19大单拉高→9:19最后撤单(骗跟风),看9:20后真实量。开盘抢筹：9:24看到买单堆积→开盘大概率高走。开盘出逃：9:24看到卖单堆积→开盘大概率下杀。尾盘集合竞价(14:57-15:00)：深市有,决定收盘价。注意事项：集合竞价量小容易被操控,小盘股/次新股更甚。期货开盘集合竞价：8:55-8:59(指令申报),8:59-9:00(撮合)。",ImageType.DIAGRAM, listOf("集合竞价","开盘价","撤单","抢筹"), listOf("basic_001","basic_013","basic_015")),
        KnowledgeItem("basic_043","盘中异动识别",Category.BASIC,Level.INTERMEDIATE,
            "分时线上的异常信号——盘中异动是短线交易的核心信息源。",
            "大单监控：单笔成交>100万元(或按流通市值比例设置),持续大单流入=主力进场信号。拉升波形：45度角匀速拉升(最健康)、90度直线拉升(游资对倒,持续差)、台阶式拉升(每段都有资金接力)。跳水识别：无抵抗下跌(放量直线杀,出货)、缩量缓跌(洗盘概率大)、关键价位跌破后的恐慌(止损盘涌出)。量比异动：量比>3(放量明显,有资金关注)、量比>10(异常放量,消息或主力动作)。盘口技巧：买一卖一挂单变化(卖一不断被吃掉但卖一价格不跌=资金吸筹,买一不断被砸但买一价格不涨=资金出逃)。尾盘2:30后拉升(一般不可靠,次日低开概率大)。尾盘2:30后杀跌(恐慌盘,但次日可能有反弹)。",ImageType.NONE, listOf("异动","大单","拉升","盘口"), listOf("strategy_018","strategy_021","basic_042")),
        KnowledgeItem("basic_044","分时图实战战法",Category.BASIC,Level.INTERMEDIATE,
            "一天内的走势藏着主力的所有意图。",
            "分时均线(黄色线)：价格在均线上方=日内强势,下方=弱势。均线支撑/压力：回踩均线不破=买点,反弹到均线不过=卖点。开盘定势：高开高走(强,追)、高开低走(弱,卖)、低开高走(转强,关注)、低开低走(弱,远离)。两种标准走势：推土机(全程在均线上方,爬升缓慢均匀,主力控盘度高)、心电图(锯齿状窄幅横盘,无方向,垃圾时间)。量价配合：涨时放量跌时缩量=健康日内趋势。涨时缩量跌时放量=主力出货。关键时间点：10:00(消化开盘情绪)、11:00-11:30(资金流向定型)、13:00-13:30(午后定调)、14:30-15:00(尾盘决战)。分时图看1分钟不如看5分钟更稳定。",ImageType.CHART, listOf("分时图","均线","量价","日内"), listOf("strategy_018","strategy_021","basic_043")),
        // ========== 国际期货 ==========
        KnowledgeItem("futures_031","CBOT农产品期货",Category.FUTURES,Level.INTERMEDIATE,
            "全球农产品定价中心——芝加哥期货交易所(CBOT)主导。",
            "CBOT核心品种：大豆(代码ZS,全球最大农产品期货)、豆粕(ZM)/豆油(ZL)套利组合。玉米(ZC,美国产量全球第一)。小麦(ZW,冬/春小麦)。三大报告：月度供需报告WASDE(每月10号左右,全球农产品定价锚)、季度库存报告、种植面积报告(6月底,全年最重要)。大豆周期：南美(巴西/阿根廷)11-3月种植,3-5月收割,此期间CBOT震荡、4-5月美国种植→天气炒作季节(6-8月最凶,厄尔尼诺/拉尼娜)→9-10月美豆收割。国内关联：豆粕主力跟随CBOT大豆(隔夜外盘涨跌直接决定次日开盘)、大豆到港量+压榨利润=大豆进口需求。农产品期货核心：天气>一切,\"农产品看供给,工业品看需求\"。",ImageType.CHART, listOf("CBOT","大豆","玉米","WASDE","天气"), listOf("futures_002","futures_012","futures_020")),
        KnowledgeItem("futures_032","LME与ICE主力品种",Category.FUTURES,Level.INTERMEDIATE,
            "除了CBOT——全球另两大商品定价中心。",
            "LME(伦敦金属交易所)：全球有色金属定价中心。铜(CA,经济晴雨表-铜博士,跟踪库存+TC/RC加工费)、铝(AH,LME+上期所双定价)、镍(NI,2022逼空事件/青山控股)、锌(ZS)、铅(PB)、锡(SN)。LME特色：3个月期货为主力合约、电子盘+场内喊价(圈内交易Ring)。ICE(洲际交易所)：原糖(SB,巴西/印度双头垄断,乙醇比价)、棉花(CT,美棉,跟踪USDA出口+全球产量)、可可(CC,西非主产,极端波动)、咖啡(KC,巴西天气)、橙汁(OJ)、布伦特原油(CO)。美元计价商品：美元走弱→商品涨(以其他货币购买力上升)。国内夜盘覆盖外盘主要交易时段(21:00-次日2:30)。内外盘套利：买外盘卖内盘(或反之)赚价差。",ImageType.DIAGRAM, listOf("LME","ICE","铜","糖","棉花"), listOf("futures_002","futures_031","macro_003")),
        KnowledgeItem("futures_033","外盘期货交易实战",Category.FUTURES,Level.INTERMEDIATE,
            "只做内盘不过瘾——外盘期货的开户与交易指南。",
            "开户渠道：境外期货公司(如盈透IB/辉立/直达国际,需境外银行卡,门槛高)、国内期货公司境外子公司(南华/横华/永安国际,门槛低但品种有限)。资金：外盘用美元/港币计价,需换汇(每人每年5万美元额度)。保证金优势：外盘保证金通常低于国内(如CBOT大豆约$2500/手vs国内豆粕约¥3000/手)。手续费：外盘以美元计价(IB约$2-3/手),无印花税。时差：美盘北京时间21:30-次日4:00(夏令时)/22:30-5:00(冬令时)。欧盘15:00-23:30。流动性：外盘主力合约连续(非国内1-5-9月),持仓量大,滑点小。核心风险：汇率风险(美元/人民币波动直接影响盈亏)、隔夜持仓(外盘波动大,黑天鹅多)、信息不对称(英文资讯、USDA报告)。",ImageType.NONE, listOf("外盘","IB","美元","汇率风险"), listOf("futures_001","futures_031","futures_032")),
        // ========== 数字货币 ==========
        KnowledgeItem("basic_045","数字货币合约入门",Category.BASIC,Level.BEGINNER,
            "比特币涨跌都能赚——永续合约是加密货币最大的创新。",
            "永续合约(Perpetual Swap)：没有到期日的期货,通过资金费率机制锚定现货价格。BTC/USDT永续、ETH/USDT永续为主力品种。杠杆：1-125x(交易所提供,但新手>5x=找死)。合约规模：BTC 0.001(BTC为单位的合约)/USDT本位(以USDT计价,更直观)。做多=买涨,做空=做跌,双向交易。强平(Liquidation)：保证金不足时系统强制平仓,瞬间归零。标记价格：用指数价格(多交易所均价)而非最新成交价计算强平(防插针操纵)。保证金模式：逐仓(每个仓位独立保证金,亏完为止)、全仓(所有资金共担,风险更高)。交易平台：币安Binance(最大)、OKX(国内用户多)、Bybit(衍生品强)。风险警告：24/7交易+高杠杆+无涨跌停=极端波动。",ImageType.NONE, listOf("数字货币","永续合约","杠杆","强平"), listOf("basic_001","futures_001","futures_002")),
        KnowledgeItem("basic_046","资金费率与套利",Category.BASIC,Level.INTERMEDIATE,
            "币圈独有的资金费率机制——套利者的印钞机。",
            "资金费率(Funding Rate)：永续合约多头与空头之间每8小时交换一次的费用(默认0.01%)。正费率=做多的人多,多头付给空头(看涨情绪过浓)。负费率=做空的人多,空头付给多头。极端费率：>0.1%/8h=过度看涨(年化>109%),< -0.05%=过度看空。套利策略：费率套利(现货买入+BTC永续做空对冲→赚取正费率,年化10-50%,低风险)。基差套利(季度合约升水>永续→买现货+卖季度到期收敛)。三角套利(BTC/USDT→ETH/BTC→ETH/USDT)。跨所套利(币安和OKX价差)。风险：交易所跑路(FTX事件,永远只用最大所)、网络拥堵(提币延迟)、费率可瞬间翻转。不推荐CEX以外的高风险套利。",ImageType.FORMULA, listOf("资金费率","套利","永续","对冲"), listOf("basic_045","futures_019","strategy_015")),
        KnowledgeItem("basic_047","链上数据与情绪分析",Category.BASIC,Level.INTERMEDIATE,
            "区块链公开透明——链上数据是最硬的基本面。",
            "链上核心指标：活跃地址数(用户增长)、交易笔数与金额(使用量)、交易所净流入(流入多=抛压大)、矿工余额(矿工卖币=顶部信号)、HODLer持仓(长期持有者数量,牛市顶峰时开始减持)。MVRV(市值/已实现市值比)：>3.7=估值过高(牛市顶部),<1=低估区间。NUPL(未实现净利润/亏损)：绿色(信仰)>蓝色(贪婪)>黄色(乐观)>橙色(希望)>红色(投降),红色=抄底区间。稳定币净流入交易所=资金在候场,抄底意愿。恐慌贪婪指数(Fear&Greed)：<25(极度恐慌=买),>75(极度贪婪=卖)。数据平台：Glassnode(最专业付费)、Dune Analytics(SQL链上分析)、Coinglass(合约数据)、CryptoQuant。",ImageType.CHART, listOf("链上","MVRV","NUPL","恐慌贪婪"), listOf("basic_045","strategy_026","macro_003")),
        // ========== 交易系统 ==========
        KnowledgeItem("strategy_029","开仓决策体系",Category.STRATEGY,Level.ADVANCED,
            "每一个开仓都应该有清晰的理由——建立你的决策框架。",
            "开仓三步法：1.环境判断——当前市场适合做多/做空/观望(看大盘趋势/成交量/VIX)。2.信号触发——出现你交易系统定义的入场信号(K线形态/指标交叉/突破)。3.风险计算——仓位=账户风险金额/止损距离(如账户10万,单笔风险2%=2000元,止损100点,则开20手)。多重确认原则：单独信号不进场,至少2-3个信号共振(如均线金叉+MACD金叉+放量)。等待最佳位置：宁可错过也不追高/追低。开仓日志(Why/What/When/How much),无日志不开仓。区分交易类型：趋势交易(顺大势逆小势入场)、反转交易(需更多证据+严格止损)、突破交易(等突破确认(收盘站稳)而非假突破)。",ImageType.NONE, listOf("开仓","信号","仓位计算","日志"), listOf("psych_006","strategy_020","risk_006")),
        KnowledgeItem("strategy_030","持仓管理与动态调整",Category.STRATEGY,Level.ADVANCED,
            "会买的是徒弟,会卖的才是师傅——持仓管理决定账户曲线。",
            "持仓三个核心问题：1.要不要继续持有(趋势还在吗？信号失效了吗？) 2.要不要加仓(趋势延续且有新信号时加仓,金字塔加仓=递减仓位) 3.要不要减仓(信号弱化/风险事件)。移动止损：盈利后把止损价不断上移(保护利润),常见方法=均线跟随(价格跌破20MA减仓)、波动率止损(ATR×2)。分批止盈：到达第一目标价平1/3,第二目标平1/3,剩下1/3让利润奔跑(跟踪止损)。最大回撤控制：从最高盈利回撤X%强制清仓(如从+5000回撤到+2000就平,保住底)。持仓心态：不要因为浮亏就死扛(破位必须走)、不要因为浮盈就想兑现(让利润奔跑)、不要频繁看盘。持仓期间禁止看别的小道消息/社交媒体。",ImageType.DIAGRAM, listOf("持仓","移动止损","分批止盈","金字塔"), listOf("strategy_029","risk_007","psych_005")),
        KnowledgeItem("strategy_031","平仓纪律与资金曲线",Category.STRATEGY,Level.ADVANCED,
            "不止是止损止盈——平仓是一套完整的退出体系。",
            "平仓三大场景：1.止损(价格到达预设止损位=无条件离场,不犹豫不幻想)。2.止盈(目标价到达/信号反转/趋势破坏,分段止盈)。3.战术平仓(重大事件前(如非农/FOMC)、长假前、账户回撤达警戒线)。保护性止损：任何仓位必须有止损,开仓同时设止损(不是亏了再想)。时间止损：入场后N根K线未按预期走(盘整/犹豫)→主动离场(时间也是成本)。日/周亏损限额：单日亏>账户3%=停手下班、单周亏>5%=下周只做模拟。资金曲线管理：资金曲线突破MA20(均线)上方=好,继续正常交易。资金曲线跌破MA20=减少仓位(半仓)。连亏5笔=强制休息1天。平仓后复盘：亏的是计划内亏损(接受)还是冲动交易(不允许),每10笔统计一次。",ImageType.CHART, listOf("平仓","止损","资金曲线","限额"), listOf("psych_006","strategy_030","risk_011")),
        // ========== 经典交易大师 ==========
        KnowledgeItem("strategy_032","巴菲特的价值投资哲学",Category.STRATEGY,Level.INTERMEDIATE,
            "把股票当成生意的一部分——巴菲特的核心理念。",
            "核心原则：1.买股票=买公司(你不是在交易代码,你是公司的部分所有者)。2.安全边际(只在你认为公司价值远高于股价时买入)。3.能力圈(不懂不投,只投资你能理解的商业模式)。4.长期持有(如果你不愿意持有10年,就10分钟都不要持有)。5.市场先生(市场是你的仆人而非主人,极端悲观时买入,极端乐观时卖出)。选股标准：ROE持续>15%、自由现金流充足、管理层优秀且诚信、护城河宽。名言：别人贪婪我恐惧,别人恐惧我贪婪。持仓集中(前5只占60%+)。近年重仓：苹果(AAPL)、可口可乐(KO)、西方石油(OXY)。巴菲特的错误：1998年错过科技股但坚守原则,2023年科技股反而成为最大持仓。",ImageType.NONE, listOf("巴菲特","价值投资","安全边际","护城河"), listOf("strategy_023","strategy_024","basic_001")),
        KnowledgeItem("strategy_033","索罗斯的反身性理论",Category.STRATEGY,Level.ADVANCED,
            "市场不仅反映现实,还改变现实——反身性是索罗斯的秘密武器。",
            "反身性(Reflexivity)：参与者的认知和市场基本面互相影响,形成一个自我强化的循环。经典句型：股价上涨→更多人关注→更多买入→股价再涨→媒体关注→更多人信→顶部泡沫。下跌同理(自我强化的恐慌螺旋)。与有效市场假说对立。泡沫三阶段：趋势形成→加速期(反身性最强)→黄昏时刻(临界点)。索罗斯操作：在趋势形成早期介入→趋势加速时加仓→临界点附近退出(感知市场即将反转)。英镑狙击(1992)：识别英镑估值与英国经济的反身性矛盾→大规模做空→英国退出ERM→英镑暴跌→索罗斯净赚10亿美元。名言：重要的不是对错,而是对的时候赚了多少、错的时候亏了多少。",ImageType.NONE, listOf("索罗斯","反身性","泡沫","临界点"), listOf("strategy_021","psych_004","macro_003")),
        KnowledgeItem("strategy_034","利弗莫尔：股票作手回忆录精华",Category.STRATEGY,Level.INTERMEDIATE,
            "100年前的教训至今依然有效——投机者的圣经。",
            "核心原则：1.趋势是你的朋友(不要与趋势对抗,等趋势确认后跟随)。2.关键点(Key Point)：价格突破某个关键位置后确认趋势(买在突破,不买在盘整)。3.试探建仓(先用小额资金测试市场,如果方向正确再逐步加仓)。4.不下注的智慧(大部分时间应该观望等待,每年只有几次真正的好机会)。5.绝不在亏损的头寸加仓(摊平亏损是最愚蠢的行为)。6.快速止损(亏损的头寸,尽快了结;盈利的头寸,给它时间奔跑)。失败教训：多次暴富又破产→因为违反自己的规则(听信内幕、感情用事、过度交易)。名言：华尔街没有新鲜事,因为投机像山岳一样古老。市场永远不变的是人性。",ImageType.NONE, listOf("利弗莫尔","趋势","关键点","止损"), listOf("strategy_020","strategy_029","psych_004")),
        KnowledgeItem("strategy_035","西蒙斯与量化革命",Category.STRATEGY,Level.ADVANCED,
            "一位数学家如何创造史上最赚钱的对冲基金。",
            "詹姆斯·西蒙斯(James Simons)：数学家/密码破译者,创立文艺复兴科技(Renaissance Technologies)。大奖章基金(Medallion Fund)：1988-2018年均回报率66%(扣除费用后39%),秒杀巴菲特。核心方法：纯量化——用数学模型和统计方法寻找市场中微小但可重复的规律,不依赖人的判断。高频统计套利：捕捉数万种资产间的短期定价偏差。关键理念：市场在极短时间内存在可预测的模式(非有效),但这些模式的信噪比极低,需要海量数据和极强算力。文艺复兴黑箱：策略完全保密,员工签终身保密协议。启示：散户无法复制但可学习——数据>直觉、纪律>灵感、长期重复>单次暴赚。差距：个人量化=回测+少量因子,机构=TB级数据+上千因子+机器学习+超低延迟。",ImageType.NONE, listOf("西蒙斯","量化","大奖章","统计套利"), listOf("strategy_025","strategy_027","strategy_013")),
        KnowledgeItem("strategy_036","达利欧的全天候策略",Category.STRATEGY,Level.ADVANCED,
            "一种在任何经济环境下都能赚钱的配置——桥水的圣杯。",
            "雷·达利欧(Ray Dalio)：桥水基金创始人,原则(Principles)作者。全天候(All Weather)：不管经济是增长/衰退、通胀/通缩,组合都能赚钱。核心逻辑：经济增长(高于/低于预期) × 通胀(高于/低于预期)=4个象限,每个象限配置不同资产。配置比例(简化版)：30%股票(标普500)、40%长期国债(20-25年)、15%中期国债(7-10年)、7.5%黄金、7.5%大宗商品。零杠杆下年化7-8%、最大回撤<15%。全天候ETF：RPAR/UPAR(美国上市)。风险平价(Risk Parity)：不是按金额平分,而是按风险贡献平分(债券波动低所以配更多来平衡股票风险)。原则：痛苦+反思=进步。极度透明+极度真实。错误日志(记录每次错误并写应对方案)。",ImageType.DIAGRAM, listOf("达利欧","全天候","风险平价","配置"), listOf("basic_027","risk_010","strategy_023")),
        // ========== 产业链分析 ==========
        KnowledgeItem("basic_048","光伏产业链拆解",Category.BASIC,Level.INTERMEDIATE,
            "从沙子到电站——光伏全产业链的投资地图。",
            "上游硅料：工业硅→多晶硅。龙头：通威股份/大全能源(西门子法)、协鑫科技(颗粒硅,成本更低)。核心变量：硅料价格(2023年从30万跌到5万/吨)、产能扩张周期(2年建设期)。中游硅片/电池片/组件：隆基/TCL中环(硅片,210mm大尺寸趋势)、通威/爱旭(电池片,TOPCon+HJT+BC技术路线之争)、晶科/天合/晶澳(组件,品牌+渠道)。下游电站：正泰电器/三峡能源(电站运营,稳定现金流)。光伏关键：产能严重过剩(全产业链亏损,行业洗牌中)、技术迭代飞快(TOPCon→HJT→钙钛矿?)、海外关税(欧美印反倾销)。投资逻辑：跟踪硅料价格拐点(硅料跌到小厂成本线=产能出清信号)、技术路线押注(HJT vs BC vs钙钛矿)。",ImageType.DIAGRAM, listOf("光伏","硅料","组件","产能过剩"), listOf("basic_037","basic_038","macro_004")),
        KnowledgeItem("basic_049","锂电产业链拆解",Category.BASIC,Level.INTERMEDIATE,
            "从锂矿到电动车——锂电全产业链的利润分配。",
            "上游资源：锂矿(天齐锂业/赣锋锂业,澳洲+南美盐湖提锂)、钴(华友钴业/洛阳钼业,刚果金)、镍(青山/格林美,印尼红土镍矿)。碳酸锂价格：从2022年60万/吨跌到2024年10万→全行业亏损。中游正极/负极/电解液/隔膜：德方纳米/容百(正极,磷酸铁锂vs三元之争)、璞泰来/杉杉(负极)、天赐材料/新宙邦(电解液)、恩捷/星源材质(隔膜,壁垒最高利润最好)。下游电池：宁德时代(全球市占37%,绝对的王者)、比亚迪(刀片电池,自供+外销)。电池回收(格林美,城市矿山)。核心跟踪：碳酸锂价格、宁德时代排产(月度)、新能源车销量。投资逻辑：产能出清(小厂退出)→龙头份额集中→利润率回升,当前处于周期底部。",ImageType.DIAGRAM, listOf("锂电","碳酸锂","宁德时代","正极"), listOf("basic_037","basic_038","basic_048")),
        KnowledgeItem("basic_050","半导体产业链拆解",Category.BASIC,Level.ADVANCED,
            "从沙子到芯片——被卡脖子最狠的产业链。",
            "设计：EDA(华大九天/概伦电子,美国三巨头Synopsys/Cadence/Mentor垄断95%)、IP核(ARM/x86)。IC设计：海思(华为,高端被制裁后自研)、韦尔股份(CIS图像传感器)、兆易创新(存储MCU)、卓胜微(射频)。制造：台积电(全球晶圆代工60%份额,3nm量产)、中芯国际(中国大陆最强但被限制先进制程,成熟制程28nm+扩产)。设备：北方华创(刻蚀/薄膜沉积,国产替代最核心标的)、中微公司(刻蚀,3nm已进台积电)、盛美上海(清洗)。材料：沪硅产业(大硅片)、安集科技(CMP抛光液)。封测：长电科技/通富微电(全球Top5)。核心矛盾：美国制裁→设备禁运→中国先进制程受限→国产替代是长期主线。投资：设备+材料是国产替代最确定的赛道。",ImageType.DIAGRAM, listOf("半导体","芯片","台积电","国产替代"), listOf("basic_037","basic_038","macro_010")),
        KnowledgeItem("basic_051","白酒行业深度分析",Category.BASIC,Level.INTERMEDIATE,
            "A股最牛赛道——白酒为什么是印钞机。",
            "行业格局：茅台(飞天,一骑绝尘,中国奢侈品)、五粮液(普五,千元价格带龙头,老二地位稳固)、泸州老窖(国窖1573,紧随其后)、次高端：山西汾酒(青花系列,品牌复兴)、洋河(梦之蓝)、古井贡酒(年份原浆)、舍得/酒鬼酒(弹性大波动也大)。白酒核心：品牌(不可复制)+渠道(经销商体系)+库存周期。Moutai现象：出厂价1169→市场价2600→差价=经销商暴利+灰色套利,提价空间巨大。白酒周期：约4-5年一轮(补库存→去库存,库存周期比经济周期更关键)。风险：茅台的金融属性(大量囤积→价格崩塌)、反腐政策、消费税改革。估值：茅台PE 25-35倍(确定性溢价),次高端弹性标的PE波动大(15-50倍)。",ImageType.NONE, listOf("白酒","茅台","库存周期","品牌"), listOf("basic_035","basic_010","basic_038")),
        KnowledgeItem("basic_052","生猪产业链与猪周期",Category.BASIC,Level.INTERMEDIATE,
            "猪肉是中国CPI的压舱石——理解猪周期是宏观交易的必修课。",
            "猪周期≈4年一轮(上涨→下跌各约2年)。原理：猪价涨→补栏母猪→10个月后生猪出栏增加→供过于求→猪价跌→淘汰母猪→10个月后供应减少→猪价涨。核心指标：能繁母猪存栏(决定10个月后的出栏量,定海神针)、猪粮比(猪价/玉米价,<5:1触发收储)、仔猪价格(补栏意愿)、出栏均重(压栏程度)。产业格局：牧原股份(工业化养殖之王,成本最低)、温氏股份/新希望/正邦科技。行业趋势：散户退出→规模化加速(CR5从6%升到20%+)。投资：猪价低位时买入牧原(成本最低,别人亏钱他亏得少),猪价高位时卖出。衍生品：生猪期货(LH,大商所)。风险：非洲猪瘟(2018年去产能30%→猪价翻3倍)、环保政策、进口猪肉。",ImageType.CHART, listOf("猪周期","能繁母猪","牧原","生猪期货"), listOf("basic_038","basic_035","futures_020")),
        // ========== Python量化实战 ==========
        KnowledgeItem("strategy_037","Python获取金融数据",Category.STRATEGY,Level.INTERMEDIATE,
            "免费开源数据——用Python拉取A股/期货/加密货币数据。",
            "Tushare(最推荐的A股数据源)：`pip install tushare`→注册获取token→`ts.pro_api()`。获取日线：`ts.pro_bar(ts_code='000001.SZ', start_date='20230101')`。免费但需积分。Baostock(无需token)：`import baostock as bs; bs.login()`→`bs.query_history_k_data_plus('sh.600000', 'date,open,high,low,close,volume')`。AkShare(国人最全)：`import akshare as ak; ak.stock_zh_a_hist(symbol='000001', period='daily')`。支持期货/外汇/宏观/海外数据。YFinance(yahoo数据)：`import yfinance as yf; yf.download('AAPL', start='2023-01-01')`(美股最方便,可能需代理)。Ccxt(加密货币)：`import ccxt; binance=ccxt.binance(); binance.fetch_ohlcv('BTC/USDT','1d')`。数据存为DataFrame→`df.to_csv('stock.csv')`。建议：日常用AkShare(数据全+无需token),严肃研究用Tushare。",ImageType.CODE, listOf("Tushare","Baostock","AkShare","数据源"), listOf("strategy_025","strategy_013","strategy_007")),
        KnowledgeItem("strategy_038","Python指标计算与信号生成",Category.STRATEGY,Level.INTERMEDIATE,
            "用Pandas和TA-Lib把技术指标算出来——只需几行代码。",
            "TA-Lib安装：`pip install TA-Lib`。MA均线：`talib.SMA(df['close'], timeperiod=20)`。MACD：`macd, signal, hist = talib.MACD(df['close'], fastperiod=12, slowperiod=26, signalperiod=9)`。RSI：`talib.RSI(df['close'], timeperiod=14)`。布林带：`upper, middle, lower = talib.BBANDS(df['close'], timeperiod=20)`。KDJ：`slowk, slowd = talib.STOCH(df['high'], df['low'], df['close'])`。信号：金叉`df['macd']> df['signal'] & df['macd'].shift(1)<= df['signal'].shift(1)`。超买超卖：`df['rsi']>70→卖出信号`。Pandas向量化操作(不用循环,快100倍)。自定义指标：`df['price_change']=df['close'].pct_change()`。`df['vol_ma']=df['volume'].rolling(20).mean()`。保存结果：`df.to_csv('with_signals.csv')`。建议：把指标计算做成可复用函数。",ImageType.CODE, listOf("TA-Lib","Pandas","指标","信号"), listOf("strategy_037","strategy_007","strategy_013")),
        KnowledgeItem("strategy_039","Python回测框架搭建",Category.STRATEGY,Level.ADVANCED,
            "从零搭建量化回测引擎——无需依赖任何第三方回测库。",
            "核心循环：`for i in range(len(df))`遍历每一根K线→判断是否持仓→有持仓检查止盈止损/出场条件→无持仓检查入场信号→模拟成交→计算盈亏。必须避坑：当前Bar收盘价开仓(使用`df.at[i,'close']`)避免使用未来数据、手续费(双边万三+滑点0.05%)、涨停/跌停不可交易(A股)。关键变量维护：`position=0, cash=1000000, trades=[]`。简单策略示例(均线金叉买入/死叉卖出)：`if df.at[i,'fast_ma'] > df.at[i,'slow_ma'] and df.at[i-1,'fast_ma']<= df.at[i-1,'slow_ma']`。输出：`total_return`, `sharpe_ratio`, `max_drawdown`, `win_rate`, 权益曲线。进阶：用Backtrader/Vnpy做更专业的回测。Backtrader：`pip install backtrader`→继承`bt.Strategy`类→重写`next()`方法。",ImageType.CODE, listOf("回测","Backtrader","盈亏","交易模拟"), listOf("strategy_038","strategy_027","strategy_028")),
        KnowledgeItem("strategy_040","Python量化可视化",Category.STRATEGY,Level.INTERMEDIATE,
            "用Matplotlib和Plotly画出专业的交易图表。",
            "K线图-Mplfinance：`pip install mplfinance`→`mpf.plot(df, type='candle', mav=(5,20,60), volume=True)`。叠加指标：`apds=[mpf.make_addplot(macd_hist, panel=2, color='gray')]`→传入`addplot=apds`。权益曲线：`plt.plot(equity_curve); plt.axhline(y=initial_cash, color='gray', linestyle='--')`。回撤图：`plt.fill_between(range(len(drawdown)), 0, drawdown, color='red', alpha=0.3)`。月度收益热力图：`sns.heatmap(monthly_returns, annot=True, cmap='RdYlGn')`。Plotly交互图：`import plotly.graph_objects as go; fig=go.Figure(data=[go.Candlestick(x=df.index, open=df.open, high=df.high, low=df.low, close=df.close)])`。交互式支持缩放/悬停,效果远超静态图。Streamlit仪表盘：`pip install streamlit`→`st.line_chart(equity_curve)`→一键生成可分享的Web界面。建议：日常快速看Mplfinance,展示用Plotly,做应用Streamlit。",ImageType.CODE, listOf("Matplotlib","Plotly","K线","可视化"), listOf("strategy_039","strategy_038","strategy_007")),
        // ========== 期权保护策略 ==========
        KnowledgeItem("options_008","保护性Put策略",Category.BASIC,Level.INTERMEDIATE,
            "给你的股票买保险——保护性Put是最简单的期权保护。",
            "策略：持有100股股票+买入1手Put(看跌期权)。买入Put=锁定最低卖出价。效果：股票跌到执行价以下→Put盈利弥补股票亏损→最大损失=执行权-当前价+权利金。股票涨→Put作废(损失权利金)=交了保险费但享受上涨。选择执行价：OTM Put(执行价<现价,保费便宜但自负额高,如5%价外Put)。ATM Put(保费贵但全额保护)。选到期日：1-3个月(来回滚动,不要买太短或太长)。适用场景：重大事件前(财报/FDA/大选/持仓股大涨后保护利润)。缺点：持续买Put保费高(长期持有成本~3-5%/年)。替代方案：领子策略(卖Call对冲买Put的成本,见下篇)。案例：持有茅台成本1500元→买入执行价1400元Put(保费20元)→茅台跌到1300,Put赚100元(1400-1300),股票亏200,净亏120元(max)。",ImageType.DIAGRAM, listOf("保护性Put","保险","对冲","Put"), listOf("options_001","options_002","options_003")),
        KnowledgeItem("options_009","领子策略组合",Category.BASIC,Level.INTERMEDIATE,
            "免费的保险——卖出Call来支付买入Put的成本。",
            "领子策略(Collar)：持有股票+买Put(保护下方)+卖Call(融资保费)。买Put支付权利金,卖Call收入权利金,如果两者相等=零成本。效果：锁定价格区间(执行价Put为下限,执行价Call为上限)。股票在区间内晃→原封不动。跌破Put执行价→Put保护起作用(等于在Put价卖出)。涨过Call执行价→股票被Call行权(以Call执行价卖出,等于卖了但有保底)。选择行权价：买OTM Put(向下5-10%)+卖OTM Call(向上5-10%)。无成本领子经典设置。适用场景：长期持有一只股票想锁定利润(如已盈利30%→锁定波动在±10%内)。风险：错过暴涨(股票翻倍但你Call执行价限制了卖出价),但至少不亏钱。损益图呈S型(下方平,中间上涨,上方平)。",ImageType.DIAGRAM, listOf("领子策略","Collar","零成本","对冲"), listOf("options_008","options_002","options_003")),
        KnowledgeItem("options_010","现金担保Put策略",Category.BASIC,Level.INTERMEDIATE,
            "不持有股票也能赚钱——卖出Put是打折买股的智慧。",
            "现金担保Put(Cash-Secured Put)：你账上有现金(或保证金),卖出一手Put(裸卖Put但用现金担保)。收入=权利金。到期：股价>执行价→Put作废→你白拿权利金(年化收益可达10-20%)。股价<执行价→买家行权→你以执行价买入股票(等于打折买入,因为拿过权利金)。本质：你愿意在某价格买股票,同时还有人付你钱(权利金)等你买。适用场景：对一只股票长期看好但觉得现价略贵,想等跌了再买→卖Put等它跌。选择执行价：卖出你愿意买入的价格的Put(如茅台现价1600,你愿意1500买→卖1500Put)。风险：股票暴跌远低于执行价(如1500卖Put结果跌到900→你也要1500买入,巨亏)。只能在愿意拥有的股票上卖Put。组合：滚动策略(Put到期后继续卖出次月Put,反复赚权利金)。",ImageType.DIAGRAM, listOf("现金担保Put","权利金","打折买股","Put"), listOf("options_008","options_001","options_002")),
        // ========== 全球股市概览 ==========
        KnowledgeItem("basic_053","美股交易制度全解",Category.BASIC,Level.INTERMEDIATE,
            "没有涨跌停、T+0、可做空——美股的制度优势与陷阱。",
            "交易时间：美东时间9:30-16:00(北京时间21:30-次日4:00夏令时/22:30-5:00冬令时),盘前4:00-9:30、盘后16:00-20:00。T+0：当日买卖无限次(但现金账户有限制,融资账户>2.5万美元可无限T+0)。无涨跌停限制(单日可翻倍也可归零)。做空：可直接做空任何股票(借股卖出),无A股的融券限制。熔断机制：标普500跌7%/13%/20%→分别暂停交易15分钟/15分钟/全天。美股账户：盈透IB(门槛低,品种全)、嘉信/富途(中文友好)。税：美国股息税30%(部分通过ETF可避)。重要指标：标普500(SPX)、纳斯达克100(NDX)、道琼斯(DJI)、VIX(恐慌指数)。散户避坑：避免毛票(Penny Stock,低价垃圾股)、小心末日期权(0DTE,纯赌博)。",ImageType.NONE, listOf("美股","T+0","做空","熔断"), listOf("basic_001","basic_015","basic_019")),
        KnowledgeItem("basic_054","港股打新与交易特色",Category.BASIC,Level.INTERMEDIATE,
            "港股介于A股和美股之间——有独特的玩法和风险。",
            "港股打新：无需市值配售(有钱就能打)、中签率远高于A股(通常5-50%)、首日不保证盈利(破发率~30%)、杠杆打新(1手5000,10倍杠杆=50万打新额度)。一手资金：通常3000-10000港币。热门股超购>100倍=散户获配极少。冷门股中签多但破发概率高。交易特点：T+0(可日内回转)、T+2交收、无涨跌停。印花税0.1%(买卖各付)。最小交易单位：1手(非1股,每只手数不同,如腾讯100股/手、美团100股/手)。港股细分：恒生指数(HSI,金融地产偏重)、恒生科技(腾讯阿里美团,中国纳斯达克)、国企指数(H股)。南向资金：通过港股通(沪港通/深港通)买港股,门槛50万。窝轮/牛熊证：港股独有衍生品(高杠杆,散户不建议)。",ImageType.NONE, listOf("港股","打新","恒生","港股通"), listOf("basic_001","basic_053","basic_015")),
        KnowledgeItem("basic_055","日本与韩国股市",Category.BASIC,Level.INTERMEDIATE,
            "日韩股市的产品和制度特色——你的亚洲配置拼图。",
            "日本：日经225(Nikkei 225,东证一部225只大盘股,类似道指,价格加权)、东证指数(TOPIX,涵盖所有一部股票,市值加权,机构更关注)。日本央行是最大买家(持有ETF约50万亿日元→约80%的日本ETF)。日元与日本股市：日元贬值→出口企业(丰田/索尼)盈利改善→日股涨(日股和日元反相关)。巴菲特2023年大举买入日本五大商社(伊藤忠/丸红/三菱/三井/住友)。散户：可买美股上市的日本ETF(EWJ/DXJ(对冲汇率))。韩国：KOSPI(主板,三星电子权重>20%,买KOSPI≈买三星)、KOSDAQ(创业板,科技/生物偏多)。韩国特色：禁止做空(多次禁令,2024年全面禁止→散户情绪涨但机构不满)。韩国散户全球最活跃(加密货币+股票)。投资：韩国ETF(EWY/USD计价,在美股买)。",ImageType.NONE, listOf("日经","韩国","ETF","三星"), listOf("basic_019","basic_053","basic_054")),
        KnowledgeItem("basic_056","欧洲股市与指数",Category.BASIC,Level.INTERMEDIATE,
            "老钱资本主义的最后堡垒——欧洲股市的特点。",
            "德国DAX(40只,制造业+汽车,西门子/大众/奔驰/宝马,欧洲最强)、法国CAC40(奢侈品半壁江山LVMH/Hermes/Loreal/开云,出口导向,欧元强弱影响大)、英国FTSE100(金融/能源/矿业偏重,最便宜的主要指数PE~12)、瑞士SMI(雀巢/罗氏/诺华,防御型,法郎避险货币)。欧洲特色：高股息(欧洲公司更愿意分红,很多指数股息率3-4%)、ESG(欧洲环保/治理标准最高)、欧元/英镑/法郎汇率(非美元计价,美元弱欧元强则欧股换算成美元回报更高)。斯托克50(EURO STOXX 50)：欧元区50只蓝筹。投资ETF：VGK(泛欧洲)/EWG(德国)/EWQ(法国)/EWU(英国),美股上市。风险：经济增长低迷(老龄化)、脱欧后英国、俄乌战争能源冲击。",ImageType.NONE, listOf("欧洲","DAX","CAC40","ETF"), listOf("basic_019","basic_053","macro_009")),
        // ========== 交易心理进阶 ==========
        KnowledgeItem("psych_007","交易成瘾与行为矫正",Category.PSYCHOLOGY,Level.INTERMEDIATE,
            "交易会像赌博一样上瘾——识别和戒断。",
            "交易成瘾症状：无法忍受空仓(总想持仓)、频繁看盘(每5分钟刷一次)、亏损后加倍交易(报复性交易)、赚钱后自信膨胀(加大仓位)、为回本而交易(不是为盈利)。成因：大脑多巴胺循环(盈利快感→渴望更多→加大仓位→亏损→更渴望回本→恶性循环)。解决方法：1.设定每日/每周最大交易次数(如每天最多3笔,达到停手)。2.物理隔离(交易时间软件上锁/委托他人保管密码)。3.强制冷却期(每次交易后至少等待30分钟再开下一单)。4.建立非交易生活(运动/学习/陪伴家人,交易不是人生的全部)。5.模拟账户过渡(实盘冲动时转为模拟,冷静后再回实盘)。核心认知：不交易不会损失什么,但冲动交易一定会亏。空仓等待是最好的交易。",ImageType.NONE, listOf("成瘾","多巴胺","空仓","戒断"), listOf("psych_004","psych_006","risk_009")),
        KnowledgeItem("psych_008","赌徒谬误与随机性",Category.PSYCHOLOGY,Level.ADVANCED,
            "连亏5次后该赢了吧？——这是你亏钱的根本原因。",
            "赌徒谬误(Gambler's Fallacy)：错误地认为独立事件的概率会受历史影响(如掷硬币连续5次正面→觉得下次反面概率大,其实还是50%)。交易表现：连亏3次后加倍仓位→\"该赢一次了\"。事实：每次交易独立(除非策略本身有序列相关),上一笔亏损不增加下一笔盈利概率。热手谬误(Hot Hand)：连赚3次后加大仓位→\"今天手气好\"。事实：过去盈利≠未来持续盈利(回归均值)。随机性认知：市场短期的涨跌≈随机游走(噪音>>信号)。一段K线图你以为是趋势但换个时间尺度可能只是随机波动。Mitigation：固定仓位(每笔都用相同的风险金额,不受上笔结果影响)。统计检验(用Runs Test验证交易序列是否随机)。接受随机(你的策略只是概率优势,不是预测未来,盈亏同源)。",ImageType.NONE, listOf("赌徒谬误","随机","概率","回归均值"), listOf("psych_004","psych_007","risk_006")),
        KnowledgeItem("psych_009","后悔厌恶与处置效应",Category.PSYCHOLOGY,Level.INTERMEDIATE,
            "为什么你总是卖飞好股票,死守烂股票。",
            "处置效应(Disposition Effect)：过早卖出盈利的→锁住利润的快感(痛苦>快乐,不想失去已赚的)。过久持有亏损的→不想割肉承认错误(害怕后悔,鸵鸟心态)。结果：账户里全是亏损股,好股票全卖飞了。后悔厌恶(Regret Aversion)：因为你害怕\"如果卖了还涨就后悔\",所以你卖飞了。因为你害怕\"如果止损了又涨回去就后悔\",所以不止损。解决方法：1.机械化止盈止损(按系统而非情绪,避免盘中决策)。2.反转视角(假设你空仓,现在问自己\"我愿意在这个价位买这只股票吗？\"——如果答案为否,那你就该卖)。3.分离自我价值(你不是你的交易,亏损≠你蠢——亏损只是概率游戏的一部分)。4.记录卖出后股票的后续走势(分析卖飞的真正原因)。",ImageType.NONE, listOf("处置效应","后悔厌恶","止损","卖飞"), listOf("psych_004","psych_005","risk_007")),
        KnowledgeItem("psych_010","锚定效应与框架偏差",Category.PSYCHOLOGY,Level.INTERMEDIATE,
            "你的成本价不该影响你的决策——但99%的人做不到。",
            "锚定效应(Anchoring)：过度依赖最先接触到的信息。交易表现：1.锚定买入价(我56买的,跌到50不想卖,等回到56再说→可能跌到30)。2.锚定历史高/低价(曾经到过100现在60=便宜→可能跌到40,曾经最低20现在40=贵了→可能涨到200)。3.锚定整数心理价位(大盘3000点是铁底,破了就好恐慌)。解决方法：重置锚点(忘记你的买入价,只看\"当前价格是否合理\",如果空仓现在会买吗？)。框架效应(Framing)：同一信息不同表述影响决策。交易表现：胜率70%=看起来很棒,但每笔盈利100亏300→实际上亏钱(期望值为负)。对策：用盈亏期望值(胜率×平均盈利-败率×平均亏损)而非单纯胜率评价策略。每日看资金曲线(净值化思维,不要只看绝对盈亏)。",ImageType.NONE, listOf("锚定效应","框架效应","决策偏差","自我欺骗"), listOf("psych_008","psych_009","risk_006")),
        // ========== 另类资产 ==========
        KnowledgeItem("basic_057","REITs投资深入",Category.BASIC,Level.INTERMEDIATE,
            "用1000块当房东——REITs让你分享商业地产的租金。",
            "REITs(Real Estate Investment Trusts)=房地产投资信托,买REITs≈买一个收租的商业地产组合(办公楼/商场/公寓/仓库)。法定要求：90%以上利润必须分红→REITs股息率高(通常4-8%)。分类：权益型(直接持有物业收租,最主流)、抵押型(买MBS/放贷,利率敏感)、混合型。美国REITs细分：数据中心(Equinix/DLR,AI算力需求爆发)、仓储(Prologis/PLD,电商物流)、住宅(AvalonBay/AVB)、零售(Simon/SPG)、医疗(Welltower/WELL)。新加坡REITs：亚洲最有经验,股息更高(5-8%),买不到美股的可选。A股：已推出公募REITs(高速公路/产业园/仓储/保障房等)。筛选：FFO(运营现金流)代替PE、股息率>4%、分红持续增长。风险：利率上升(REITs和债券是竞品,利率升REITs跌)、商业地产衰退(远程办公打败办公楼)、管理费高。",ImageType.NONE, listOf("REITs","股息","地产","分红"), listOf("basic_011","basic_010","basic_057")),
        KnowledgeItem("basic_058","碳交易与绿色金融",Category.BASIC,Level.INTERMEDIATE,
            "碳排放权成为可交易的资产——碳市场是下一个万亿赛道。",
            "碳市场机制：政府发放碳排放配额(1吨CO2=1个配额)→企业有多余配额可卖,不足的可买→通过市场机制减排。中国碳市场(2021启动)：目前只纳入发电行业(2000+企业),年覆盖约45亿吨CO2→全球最大。碳价：2024年中国碳价约70-100元/吨(欧洲EU ETS约60-80欧元/吨,差距显示中国碳价上升空间)。EU ETS：运行最久最成熟,2023碳关税CBAM正式启动(进口到欧盟的钢铁/水泥/铝/化肥等需购买碳配额)。CCER(中国核证自愿减排)：林业/风电/光伏项目可申请CCER→卖给控排企业,重启后2024年签发。投资：无直接散户标的(碳期货未对散户开放)、间接(碳交易所参股公司：深圳能源/华能国际)。绿色债券：资金定向用于环保项目,收益率略低于普通债。ESG基金：散户最方便参与方式。",ImageType.NONE, listOf("碳交易","碳排放","CCER","绿色金融"), listOf("basic_032","macro_004","macro_006")),
        KnowledgeItem("basic_059","波动率指数与VIX产品",Category.BASIC,Level.ADVANCED,
            "恐慌不仅是情绪,还是可以交易的商品。",
            "VIX(=CBOE波动率指数)：根据标普500期权价格反推的30天预期波动率(年化)。VIX=15(正常,约1%日均波动)、VIX=25-30(恐慌,约2%日均波动)、VIX>40(极端恐慌,2008年到过80,2020新冠也破80)。VIX特性：均值回归(长期均值~19)、非对称(涨快跌慢,恐慌瞬间爆发、消退缓慢)、与股市负相关(80%时间,VIX涨标普跌)。交易VIX：不能直接买VIX(它是计算值),可通过VIX期货/VXX ETF/UVXY杠杆ETF。VXX(做多VIX短期期货,长期必跌(展期损耗),只适合极短期做多恐慌)。SVXY(做空VIX,长期向上但恐慌时可能归零,2018年Volmageddon事件一天跌90%+)。VIX期权(专业做市商领域)。散户：不推荐交易VIX产品(复杂+高损耗),仅用作宏观观察指标。A股对应：50ETF期权隐含波动率(类似功能)。",ImageType.CHART, listOf("VIX","波动率","恐慌","期权"), listOf("options_005","strategy_026","macro_003")),
        // ========== 经典战役 ==========
        KnowledgeItem("basic_060","索罗斯狙击英镑(1992)",Category.BASIC,Level.BEGINNER,
            "一个人打败一个国家央行——金融史上最著名的交易。",
            "背景：英国加入欧洲汇率机制(ERM),将英镑与德国马克挂钩(1英镑≈2.95马克,±6%浮动)。但1992年英国经济衰退+高通胀,德国统一后经济过热+高利率→英镑无法维持高汇价。索罗斯的判断：英镑严重高估,英国要么大幅加息(经济崩溃)、要么退出ERM让英镑暴跌。索罗斯操作：借入英镑(通过量子基金杠杆)→换成德国马克→同时做空英镑/买入英镑看跌期权。头寸：做空100亿美元等值英镑(当时最大的单笔交易)。黑周三(9月16日)：英国央行两次加息(10%→12%→15%)徒劳无功→当晚宣布退出ERM→英镑暴跌15%。索罗斯：单笔盈利10亿美元,全年基金收益68%,赚了20亿美元。英国：花了33亿英镑外汇储备护盘(无偿),财政大臣引咎辞职。教训：央行在趋势面前也无力回天。",ImageType.NONE, listOf("索罗斯","英镑","黑周三","外汇"), listOf("strategy_033","macro_003","macro_010")),
        KnowledgeItem("basic_061","次贷危机大空头(2008)",Category.BASIC,Level.BEGINNER,
            "少数人提前看到房地产崩盘并从中获利数十亿。",
            "背景：2000年代美国房地产泡沫→银行把次贷包装成MBS/CDO卖给全球投资者→评级机构给垃圾债券AAA评级。几个做空者：Michael Burry(对冲基金经理,Scion Capital,最早发现次贷问题,通过CDS(信用违约互换)做空次贷债券→2年等待→2008年盈利1亿美元)。Steve Eisman(FrontPoint→做空次贷银行股票→\"所有的一切都是谎言\")。Greg Lippmann(德意志银行交易员→推动CDS市场→让更多机构做空次贷)。CDS机制：类似保险→定期支付保费(保费低)→次贷违约→一次性获赔巨额。做空过程(最痛苦)：2005年开始做空→2006-2007年次贷问题持续恶化但CDS不涨(市场不反应)→Burry面临客户撤资→2008年爆发→\"终于\"。关键教训：1.市场可能长时间非理性(比你能扛的时间还长) 2.做空的时机是最难的(你对了但这个对需要很长时间兑现)。",ImageType.NONE, listOf("次贷","CDS","做空","2008"), listOf("basic_031","psych_004","risk_004")),
        KnowledgeItem("basic_062","游戏驿站逼空大战(2021)",Category.BASIC,Level.BEGINNER,
            "散户团结起来掀翻华尔街——社交媒体时代的交易革命。",
            "背景：GameStop(GME,游戏实体零售店)→被疫情+线上游戏双重打击→股价长期低迷($4-20)。华尔街空头：Melvin Capital等对冲基金极度看空GME,做空比例高达140%(借了>公司总股本的空头股票)。Reddit散户(华尔街赌注WSB)：在r/wallstreetbets发现GME被过度做空→号召散户集体买入→\"逼空\"(short squeeze)。过程：2021年1月中旬GME从$20启动→1月28日冲到$483(盘中)→上涨2400%。Robinhood等券商暂停GME买入(只许卖不允许买)→引发国会听证→Robinhood被骂上全球热搜。结果：部分早进散户赚了数十万美元,高位追入的损失惨重。Melvin Capital等空头亏损超200亿美元(1月单月),后来被迫清盘。启示：1.做空比例过度高→本身就是风险信号(逼空风险) 2.社交媒体改变了信息传播和市场博弈 3.FOMO和贪婪仍是散户最大敌人(很多人在$400+买入后套牢)。",ImageType.NONE, listOf("GME","逼空","散户","做空"), listOf("basic_053","psych_008","psych_004"))
    )
    fun search(query: String): List<KnowledgeItem> {
        if (query.isBlank()) return emptyList()
        val q = query.lowercase()
        return allItems.filter { it.title.lowercase().contains(q) || it.summary.lowercase().contains(q) || it.content.lowercase().contains(q) || it.tags.any { it.lowercase().contains(q) } || it.category.label.lowercase().contains(q) }
    }
    fun getByCategory(c: Category) = allItems.filter { it.category == c }
    fun getByLevel(l: Level) = allItems.filter { it.level == l }
}

